-.btn-submit { width: 100%; padding: 1rem; background: var(--brand); color: #fff; border: 0; font-family: var(--font-display); font-size: .6875rem; font-weight: 600; letter-spacing: .2em; text-transform: uppercase; cursor: pointer; display: flex; align-items: center; justify-content: center; gap: .5rem; transition: all .3s var(--ease); }
-.btn-submit:hover { filter: brightness(1.08); }
-.btn-submit .arr { transition: transform .3s var(--ease); }
-.btn-submit:hover .arr { transform: translateX(4px); }
-
-/* Contact panel */
-.contact-scrim { position: fixed; inset: 0; z-index: 59; background: rgba(0,0,0,.6); opacity: 0; pointer-events: none; transition: opacity .4s var(--ease); }
-.contact-scrim.open { opacity: 1; pointer-events: auto; }
