-.panel-close:hover { border-color: var(--brand); color: var(--brand); }
-.panel-body { flex: 1; overflow-y: auto; padding: 1.5rem; }
-.panel-footer { padding: 1.5rem; border-top: 1px solid rgba(255,255,255,.05); font-size: .6875rem; letter-spacing: .15em; text-transform: uppercase; color: rgba(176,170,165,.4); }
-.enq-field { width: 100%; padding: .75rem 1rem; background: var(--panel2); border: 1px solid rgba(255,255,255,.18); color: var(--sand); font-family: var(--font-sans); font-size: .85rem; transition: border-color .25s var(--ease); }
-.enq-field:focus { outline: none; border-color: var(--brand); background: #333; }
-.enq-field::placeholder { color: var(--stone); }
-.enq-submit { display: inline-flex; align-items: center; gap: .5rem; padding: .75rem 2rem; background: var(--brand); color: #fff; border: 0; font-family: var(--font-display); font-size: .6875rem; font-weight: 600; letter-spacing: .15em; text-transform: uppercase; cursor: pointer; transition: all .3s var(--ease); }
-.enq-submit:hover { filter: brightness(1.08); transform: translateY(-2px); }
-
-/* CTA banner */
-.cta-banner { background: var(--brand); padding: 4rem 0; }
-.cta-go { display: inline-flex; align-items: center; gap: .5rem; padding: 1rem 2rem; background: var(--ink); color: #fff; text-transform: uppercase; letter-spacing: .15em; font-family: var(--font-display); text-decoration: none; transition: all .3s var(--ease); }
-.cta-go:hover { filter: brightness(1.2); }
-
-/* Footer */
-.site-footer { border-top: 1px solid rgba(255,255,255,.05); padding: 3rem 0; }
-.footer-inner { display: flex; flex-direction: column; align-items: center; justify-content: space-between; gap: 1.5rem; }
-@media (min-width: 640px) { .footer-inner { flex-direction: row; } }
-.footer-nav { display: flex; flex-wrap: wrap; justify-content: center; gap: 1.5rem; }
