  currency: string;
  availability: "available" | "busy" | "booked";
  rating: number;
  reviews_count: number;
  wins_count: number;
  is_featured: number;
  is_verified: number;
  contact_email: string | null;
  social_links: Record<string, string>;
  portfolio_items: unknown[];
  created_at: number;
  updated_at: number;
