export function createReview(input: {
  marketer_id: string;
  workspace_id: string;
  engagement_id?: string;
  rating: number;
  title?: string;
  body?: string;
  author_name?: string;
}): Review {
  const id = uid("rev_");
  const t = now();
  db.prepare(
    `
    INSERT INTO marketer_reviews (id, marketer_id, workspace_id, engagement_id, rating, title, body, author_name, created_at)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
