export type Severity = "critical" | "high" | "medium" | "low";
export type CheckStatus = "pass" | "warning" | "fail";
export type BusinessType = "saas" | "ecommerce" | "local-service" | "b2b-enterprise" | "info-products" | "mobile-app" | "real-estate" | "healthcare" | "finance" | "agency" | "generic";

export interface AuditCheck {
  id: string;
  platform: Platform;
  category: string;
  title: string;
  description: string;
  severity: Severity;
  weight: number;
  status: CheckStatus;
  impact?: string;
  action?: string;
  owner?: string;
  eta_days?: number;
}

export interface PlatformScore {
  platform: Platform;
  score: number;
  grade: string;
  checks_run: number;
  critical: number;
  high: number;
  findings: AuditCheck[];
}

export interface AdsHealthReport {
  ads_health_score: number;
  grade: string;
  audit_date: string;
  platforms: Record<string, PlatformScore>;
  top_findings: AuditCheck[];
  quick_wins: string[];
  budget_rec?: BudgetRec;
  creative_rec?: CreativeRec;
}

export interface BudgetRec {
  monthly_budget: number;
  allocation: Record<string, number>;
  rationale: string;
}

export interface CreativeRec {
  concepts: string[];
  platforms: string[];
  pillars: string[];
}

export interface HypothesisTest {
  hypothesis: string;
  metric: string;
  expected_lift: string;
  baseline_rate: number;
  mde: number;
  sample_size_per_variant: number;
  daily_traffic: number;
  duration_days: number;
  platform_setup: string;
  success_criteria: string;
}

export interface BrandProfile {
  name: string;
  url?: string;
  voice: {
    formal_casual: number;
    bold_subtle: number;
    rational_emotional: number;
  };
  descriptors: string[];
  audience: string;
  value_props: string[];
  differentiators: string[];
  colors?: { primary: string; secondary: string };
  industry?: string;
  business_type?: BusinessType;
}

export interface CampaignBrief {
  concepts: CampaignConcept[];
  platforms: string[];
  objective: string;
  budget_guidance: string;
  kpi_targets: Record<string, string>;
}

export interface CampaignConcept {
  name: string;
  angle: string;
  messaging_pillar: string;
  platforms: string[];
  target_audience: string;
  creative_direction: string;
  kpi_target: string;
}

export interface ContentCalendarDay {
  date: string;
  platform: string;
  content_type: string;
  hook: string;
  caption: string;
  cta: string;
  hashtags: string[];
  status: "draft" | "scheduled" | "published";
}

export interface EmailSequence {
  name: string;
  emails: EmailStep[];
  segment: string;
  trigger: string;
}

export interface EmailStep {
  day: number;
  subject: string;
  body: string;
  cta: string;
  delay_hours?: number;
}

export interface CompetitorIntel {
  competitor: string;
  url: string;
  positioning: string;
  platforms: string[];
  messaging_themes: string[];
  estimated_spend: string;
  gaps: string[];
  opportunities: string[];
}

export interface LandingAnalysis {
  url: string;
  score: number;
  performance: {
    lcp_ms?: number;
    cls?: number;
    ttfb_ms?: number;
  };
  content: {
    title?: string;
    h1?: string;
    meta_description?: string;
  };
  issues: string[];
  recommendations: string[];
}

