import type { AuditCheck, Severity, CheckStatus } from "./types";

export const SEVERITY_MULTIPLIER: Record<Severity, number> = {
  critical: 5.0,
  high: 2.5,
  medium: 1.0,
  low: 0.25,
};

export function calculateWeightedScore(checks: AuditCheck[]): number {
  if (checks.length === 0) return 0;
  let earned = 0;
  let total = 0;
  for (const c of checks) {
    const w = c.weight * (SEVERITY_MULTIPLIER[c.severity] || 1);
    if (c.status === "pass") {
      earned += w;
    } else if (c.status === "warning") {
      earned += w * 0.5;
    }
    total += w;
  }
  return total === 0 ? 0 : Math.round((earned / total) * 100);
}

export function scoreToGrade(score: number): string {
  if (score >= 90) return "A";
  if (score >= 75) return "B";
  if (score >= 60) return "C";
  if (score >= 40) return "D";
  return "F";
}

export function summarizePlatforms(checks: AuditCheck[]): Record<string, { score: number; grade: string; checks_run: number; critical: number; high: number; findings: AuditCheck[] }> {
  const groups: Record<string, AuditCheck[]> = {};
  for (const c of checks) {
    if (!groups[c.platform]) groups[c.platform] = [];
    groups[c.platform].push(c);
  }
  const out: Record<string, { score: number; grade: string; checks_run: number; critical: number; high: number; findings: AuditCheck[] }> = {};
  for (const [platform, platformChecks] of Object.entries(groups)) {
    const score = calculateWeightedScore(platformChecks);
    out[platform] = {
      score,
      grade: scoreToGrade(score),
      checks_run: platformChecks.length,
      critical: platformChecks.filter(c => c.severity === "critical" && c.status !== "pass").length,
      high: platformChecks.filter(c => c.severity === "high" && c.status !== "pass").length,
      findings: platformChecks.filter(c => c.status !== "pass"),
    };
  }
  return out;
}

export function prioritizeFindings(checks: AuditCheck[]): AuditCheck[] {
  const failed = checks.filter(c => c.status !== "pass");
  return failed.sort((a, b) => {
    const sa = SEVERITY_MULTIPLIER[a.severity] || 0;
    const sb = SEVERITY_MULTIPLIER[b.severity] || 0;
    if (sb !== sa) return sb - sa;
    return (b.eta_days || 99) - (a.eta_days || 99);
  });
}

export function detectBusinessType(checks: AuditCheck[]): string {
  const platformCount = new Set(checks.map(c => c.platform)).size;
  if (platformCount >= 5) return "agency";
  if (checks.some(c => c.platform === "amazon")) return "ecommerce";
  if (checks.some(c => c.platform === "apple" || c.platform === "tiktok")) return "mobile-app";
  if (checks.some(c => c.id.startsWith("L"))) return "b2b-enterprise";
  if (checks.some(c => c.id.startsWith("G") && c.category === "Keywords & Quality Score")) return "saas";
  return "generic";
}

export function generateQuickWins(findings: AuditCheck[]): string[] {
  const wins: string[] = [];
  for (const f of findings) {
    if ((f.severity === "critical" || f.severity === "high") && f.eta_days && f.eta_days <= 1 && f.action) {
      wins.push(f.action);
    }
    if (wins.length >= 5) break;
  }
  return wins;
}

