import type { AuditCheck, AdsHealthReport, PlatformScore, BusinessType } from "./types";
import { buildGoogleChecks } from "./google";
import { buildMetaChecks } from "./meta";
import { buildLinkedInChecks } from "./linkedin";
import { buildTikTokChecks } from "./tiktok";
import { buildMicrosoftChecks } from "./microsoft";
import { buildAppleChecks } from "./apple";
import { buildAmazonChecks } from "./amazon";
import { buildCrossPlatformChecks } from "./cross";
import { calculateWeightedScore, scoreToGrade, summarizePlatforms, prioritizeFindings, generateQuickWins, detectBusinessType } from "../scoring";

export async function runAudit(input: {
  platforms: string[];
  businessType?: string;
  industry?: string;
  monthlySpend?: number;
  data: Record<string, Record<string, unknown>>;
}): Promise<AdsHealthReport> {
  const allChecks: AuditCheck[] = [];
  for (const p of input.platforms) {
    switch (p) {
      case "google": allChecks.push(...buildGoogleChecks(input.data.google || {})); break;
      case "meta": allChecks.push(...buildMetaChecks(input.data.meta || {})); break;
