function generateBudgetRec(businessType: BusinessType, monthlySpend: number) {
  const proven = Math.round(monthlySpend * 0.7);
  const scaling = Math.round(monthlySpend * 0.2);
  const testing = Math.round(monthlySpend * 0.1);
  const allocation: Record<string, number> = {};
  switch (businessType) {
    case "saas":
      allocation.google = proven;
      allocation.linkedin = scaling;
      allocation.meta = testing;
      break;
    case "ecommerce":
      allocation.google = proven;
      allocation.meta = scaling;
      allocation.tiktok = testing;
      break;
    case "b2b-enterprise":
      allocation.linkedin = proven;
      allocation.google = scaling;
      allocation.meta = testing;
      break;
    case "agency":
      allocation.google = Math.round(monthlySpend * 0.4);
      allocation.meta = Math.round(monthlySpend * 0.3);
      allocation.linkedin = Math.round(monthlySpend * 0.2);
      allocation.tiktok = Math.round(monthlySpend * 0.1);
      break;
    default:
      allocation.google = proven;
      allocation.meta = scaling;
      allocation.linkedin = testing;
  }
  return {
    monthly_budget: monthlySpend,
    allocation,
    rationale: `70/20/10 split for ${businessType}. Proven channels receive the majority; scaling and testing budgets are sized for learning phase requirements.`,
  };
}

function generateCreativeRec(businessType: BusinessType, platforms: string[]) {
  const concepts: string[] = [];
  const pillars: string[] = [];
  switch (businessType) {
    case "saas":
      concepts.push("Trial activation: problem-first demo short");
      concepts.push("Social proof: customer testimonial carousel");
      pillars.push("Problem-Solution-Social Proof-CTA");
      break;
    case "ecommerce":
      concepts.push("Product hero with UGC overlay");
      concepts.push("Offer-driven carousel with urgency");
      pillars.push("Hero-Offer-Proof-CTA");
      break;
    case "b2b-enterprise":
      concepts.push("Thought leadership: insight-driven whitepaper tease");
      concepts.push("ROI calculator demo");
      pillars.push("Insight-Credibility-Offer-CTA");
      break;
    default:
      concepts.push("Pain-point emotional hook");
      concepts.push("Before/after transformation");
      pillars.push("Hook-Story-Offer-CTA");
  }
  return { concepts, platforms, pillars };
}

export function calculatePPC(args: {
  cpa?: number;
  targetCpa?: number;
  roas?: number;
  targetRoas?: number;
  cpl?: number;
  targetCpl?: number;
  clicks?: number;
  cpc?: number;
  cvr?: number;
  revenue?: number;
  spend?: number;
  ltv?: number;
  cac?: number;
  margin?: number;
  acos?: number;
  taco?: number;
}) {
  const results: Record<string, number> = {};
  if (args.cpa && args.targetCpa) results.cpa_efficiency = Number(((args.targetCpa / args.cpa) * 100).toFixed(1));
  if (args.roas && args.targetRoas) results.roas_efficiency = Number(((args.roas / args.targetRoas) * 100).toFixed(1));
  if (args.clicks && args.cpc) results.total_clicks = args.clicks;
  if (args.clicks && args.cpc) results.total_spend = Number((args.clicks * args.cpc).toFixed(2));
  if (args.clicks && args.cvr) results.conversions = Number((args.clicks * (args.cvr / 100)).toFixed(1));
  if (args.spend && args.revenue) results.roas = Number((args.revenue / args.spend).toFixed(2));
  if (args.ltv && args.cac) results.ltv_cac_ratio = Number((args.ltv / args.cac).toFixed(2));
  if (args.cpa) results.break_even_cpa = args.margin ? Number((args.margin * 100).toFixed(1)) : 0;
  if (args.mer) results.mer = args.mer;
  if (args.acos && args.margin) results.acos_health = Number(((args.acos / args.margin) * 100).toFixed(1));
  return results;
}

export function designABTest(args: {
  baseline_rate: number;
  mde: number;
  daily_traffic: number;
  variants?: number;
}) {
  const confidence = 0.95;
  const power = 0.8;
  const z_alpha = 1.96;
  const z_beta = 0.84;
  const p = args.baseline_rate / 100;
  const mde = args.mde / 100;
  const variants = args.variants || 2;

  const perVariant = Math.ceil(((z_alpha + z_beta) ** 2 * 2 * p * (1 - p)) / (mde ** 2));
  const totalSample = perVariant * variants;
  const dailyPerVariant = Math.floor(args.daily_traffic / variants);
  const duration = Math.max(7, Math.ceil(perVariant / dailyPerVariant));

  return {
    sample_size_per_variant: perVariant,
    total_sample: totalSample,
    duration_days: duration,
    daily_traffic_per_variant: dailyPerVariant,
    confidence,
    power,
    mde_percent: mde * 100,
    platform_setup: variants === 2
      ? "A/B test — use platform experiment tools (Meta Experiments, Google Drafts/Experiments)"
      : `Multivariate test (${variants} variants) — ensure sufficient traffic per variant`,
    success_criteria: `Detect ${mde * 100}% lift with ${confidence * 100}% confidence / ${power * 100}% power over ${duration} days`,
  };
}

