input.content:
import type { BrandProfile, CampaignBrief, CampaignConcept, ContentCalendarDay, EmailSequence, CompetitorIntel, LandingAnalysis } from "./types";

export async function generateCopy(brief: { brand: BrandProfile; platform: string; objective: string; angle?: string; count?: number }): Promise<string[]> {
  const count = brief.count || 5;
  const headlines: string[] = [];
  const voice = brief.brand.voice;
  const descriptors = brief.brand.descriptors || [];

  for (let i = 0; i < count; i++) {
    const templates = getHeadlineTemplates(brief.platform, brief.objective);
    const template = templates[i % templates.length];
    const valProp = brief.brand.value_props[0] || "transform your results";
    const differentiator = brief.brand.differentiators[0] || "";
    headlines.push(template
      .replace("{val_prop}", valProp)
      .replace("{differentiator}", differentiator)
      .replace("{descriptor}", descriptors[i % descriptors.length] || "effortlessly")
    );
  }
  return headlines;
}

function getHeadlineTemplates(platform: string, objective: string): string[] {
  if (platform === "google") {
    return [
      "{descriptor} {val_prop} — Start Free Today",
      "Stop Struggling With {val_prop}. Try {differentiator}.",
      "{val_prop} in Minutes, Not Months. See How.",
      "The {differentiator} Way to {val_prop}",
      "{descriptor} {val_prop} — Rated #1 by Teams",
    ];
  }
  if (platform === "meta" || platform === "tiktok") {
    return [
      "POV: You finally found a {val_prop} that actually works",
      "This {differentiator} trick changed everything for us",
      "Why 10,000+ teams switched to {val_prop}",
      "We tried 12 tools. This is the only one that delivered {val_prop}.",
      "The {descriptor} secret to {val_prop} (nobody talks about this)",
    ];
  }
  if (platform === "linkedin") {
    return [
      "How we achieved {val_prop} without the usual pain",
      "{differentiator}: the framework that changed our {val_prop} strategy",
      "After 6 months of testing, here's what actually drives {val_prop}",
      "Most teams get {val_prop} wrong. Here's the fix.",
      "{descriptor} insights on {val_prop} for 2026",
    ];
  }
  return [
    "Discover {val_prop} — {descriptor} and simple",
    "Unlock {val_prop} with {differentiator}",
    "Transform your {val_prop} starting today",
    "The smarter way to {val_prop}",
    "{descriptor} {val_prop} for modern teams",
  ];
}

export async function generateEmailSequence(brief: { brand: BrandProfile; topic: string; segment: string; length?: number }): Promise<EmailSequence> {
  const emails: EmailStep[] = [];
  const valProp = brief.brand.value_props[0] || "achieve better results";
  const differentiator = brief.brand.differentiators[0] || "a simpler approach";

  for (let i = 1; i <= (brief.length || 5); i++) {
    if (i === 1) {
      emails.push({
        day: i,
        subject: `Welcome — here's what's next for ${brief.brand.name}`,
        body: `Hi there,\n\nWelcome to ${brief.brand.name}. We're here to help you ${valProp} through ${differentiator}.\n\nHere's what to expect next:\n- Day 1: Quick setup guide\n- Day 3: Pro tips from the team\n- Day 7: How top users ${valProp}\n\nReply anytime — we read every message.\n\nCheers,\nThe ${brief.brand.name} Team`,
        cta: "Complete your setup",
      });
    } else if (i === 3) {
      emails.push({
        day: i,
        subject: `3 things the top 10% do differently`,
        body: `Most people ${valProp} the hard way. Here's what the top 10% know:\n\n1. Start with the end in mind\n2. Measure the right metrics\n3. Iterate fast\n\n${brief.brand.name} automates all three.\n\nSee how it works in 2 minutes.`,
        cta: "Watch the demo",
      });
    } else if (i === 5) {
      emails.push({
        day: i,
        subject: `Your first results are coming in`,
        body: `You've been using ${brief.brand.name} for a week now. Time to look at the data.\n\nUsers who complete their first project see results within 7 days. Ready for yours?`,
        cta: "View your dashboard",
      });
    } else {
      emails.push({
        day: i,
        subject: `One question about ${brief.topic}`,
        body: `Quick check-in: how's ${brief.topic} going?\n\nIf you're stuck, we're here to help. If you're already seeing wins, we'd love to hear about it.\n\nReply and let us know.`,
        cta: "Share your progress",
      });
    }
  }
  return { name: `${brief.topic} — ${brief.segment}`, emails, segment: brief.segment, trigger: "enrollment" };
}

export async function generateSocialCalendar(brief: { brand: BrandProfile; platforms: string[]; days?: number }): Promise<ContentCalendarDay[]> {
  const days = brief.days || 30;
  const calendar: ContentCalendarDay[] = [];
  const valProp = brief.brand.value_props[0] || "better results";
  const differentiator = brief.brand.differentiators[0] || "";
  const hooks = [
    `Stop wasting time on ${valProp}`,
    `The ${differentiator} hack nobody talks about`,
    `I asked 100 teams about ${valProp}...`,
    `What if ${valProp} was actually easy?`,
    `${brief.brand.name} just shipped something big for ${valProp}`,
    `The #1 mistake I see with ${valProp}`,
    `Here's the exact playbook we use for ${valProp}`,
    `Unpopular opinion: you don't need more tools for ${valProp}`,
  ];
  const captions = [
    `${valProp} doesn't have to be complicated. Here's what changed for us.`,
    `${differentiator} — and it took us 3 months to figure it out.`,
    `Real talk: most teams overcomplicate ${valProp}. Simplify.`,
    `Saving this for the next time someone says ${valProp} is hard.`,
    `Behind the scenes of how we ${valProp}.`,
  ];
  const ctas = ["Learn more", "Try it free", "Get the guide", "Join the waitlist", "Book a demo", "Download now"];
  const hashtags = ["#marketing", "#growth", "#saas", "#ecommerce", "#b2b", "#digitalmarketing", "#strategy", "#automation"];

  for (let i = 0; i < days; i++) {
    const date = new Date();
    date.setDate(date.getDate() + i);
    const platform = brief.platforms[i % brief.platforms.length];
    calendar.push({
      date: date.toISOString().split("T")[0],
      platform,
      content_type: i % 4 === 0 ? "video" : i % 4 === 1 ? "carousel" : i % 4 === 2 ? "image" : "text",
      hook: hooks[i % hooks.length],
      caption: captions[i % captions.length],
      cta: ctas[i % ctas.length],
      hashtags: [hashtags[i % hashtags.length], hashtags[(i + 1) % hashtags.length]],
      status: i < 3 ? "draft" : i < 10 ? "scheduled" : "draft",
    });
  }
  return calendar;
}

export async function generateCompetitorIntel(brief: { brand: BrandProfile; competitors: string[] }): Promise<CompetitorIntel[]> {
  return brief.competitors.map((comp, i) => ({
    competitor: comp,
    url: `https://${comp.toLowerCase().replace(/\s+/g, "")}.com`,
    positioning: `Positions themselves as the ${brief.brand.differentiators[0] || "leading"} solution for ${brief.brand.audience}`,
    platforms: ["google", "meta", "linkedin"],
    messaging_themes: ["innovation", "trust", "speed", "support"],
    estimated_spend: i === 0 ? "High ($50K+/mo)" : i === 1 ? "Medium ($10K-$50K/mo)" : "Low (<$10K/mo)",
    gaps: [
      "Weak social proof on landing pages",
      "No clear differentiation in ad copy",
      "Missing retargeting sequences",
    ],
    opportunities: [
      `Emphasize ${brief.brand.differentiators[0] || "unique value"} in ad copy`,
      "Launch thought leadership campaign on LinkedIn",
      "Create comparison landing pages",
    ],
  }));
}

export async function analyzeLanding(url: string): Promise<LandingAnalysis> {
  return {
    url,
    score: 65,
    performance: {
      lcp_ms: 2400,
      cls: 0.12,
      ttfb_ms: 400,
    },
    content: {
      title: "Example Title",
      h1: "Main Headline",
      meta_description: "Meta description here",
    },
    issues: [
      "LCP > 2.5s — compress hero image and enable caching",
      "CLS > 0.1 — reserve space for dynamic content",
      "Missing structured data (Product/Organization schema)",
      "No visible CTA above the fold",
    ],
    recommendations: [
      "Add a clear, benefit-driven H1 within 200ms of load",
      "Place primary CTA above the fold with contrasting color",
      "Add trust signals (testimonials, badges, reviews) near CTA",
      "Implement schema.org markup for rich snippets",
      "Reduce form fields to <= 5 for higher conversion",
    ],
  };
}

export async function analyzeFunnel(url: string): Promise<{ stages: { name: string; dropoff: number; issues: string[] }[]; overall_score: number }> {
  return {
    stages: [
      { name: "Awareness", dropoff: 0.65, issues: ["Low organic visibility", "Weak ad messaging"] },
      { name: "Interest", dropoff: 0.45, issues: ["Long page load", "Missing content upgrades"] },
      { name: "Consideration", dropoff: 0.60, issues: ["No comparison content", "Weak social proof"] },
      { name: "Decision", dropoff: 0.30, issues: ["Complex checkout", "Hidden pricing"] },
      { name: "Retention", dropoff: 0.20, issues: ["No onboarding sequence", "No win-back flow"] },
    ],
    overall_score: 42,
  };
}

export async function analyzeBrand(url: string): Promise<{ voice: { formal_casual: number; bold_subtle: number; rational_emotional: number }; descriptors: string[]; consistency_score: number; recommendations: string[] }> {
  return {
    voice: { formal_casual: 4, bold_subtle: 7, rational_emotional: 3 },
    descriptors: ["direct", "confident", "bold", "clear"],
    consistency_score: 68,
    recommendations: [
      "Strengthen tone consistency across pages",
      "Add brand voice guidelines to style guide",
      "Align headline messaging with page content",
    ],
  };
}

