import type { BrandProfile } from "./types";

export interface PersonaProfile extends BrandProfile {
  created_at: string;
  updated_at: string;
  platforms: Record<string, PlatformPersona>;
  insights: string[];
}

export interface PlatformPersona {
  tone: string;
  structure: string;
  length: "short" | "medium" | "long";
  content_types: string[];
  optimization_notes: string[];
}

const defaultPersona: Omit<PersonaProfile, "name" | "created_at" | "updated_at"> = {
  voice: { formal_casual: 5, bold_subtle: 5, rational_emotional: 5 },
  descriptors: ["professional", "clear", "helpful"],
  audience: "General audience",
  value_props: ["Save time", "Increase revenue", "Reduce cost"],
  differentiators: ["Easy to use", "Great support", "Proven results"],
  platforms: {
    linkedin: {
      tone: "professional",
      structure: "hook → insight → CTA",
      length: "medium",
      content_types: ["article", "carousel", "text post"],
      optimization_notes: ["Use line breaks for scannability", "Tag relevant people/companies", "Post Tuesday-Thursday 8am-10am"],
    },
    twitter: {
      tone: "casual",
      structure: "hot take → explanation → thread",
      length: "short",
      content_types: ["thread", "single tweet", "poll"],
      optimization_notes: ["Threads outperform single tweets", "Add visual to first tweet", "Reply to 5 tweets before posting"],
    },
    facebook: {
      tone: "casual",
      structure: "story → lesson → CTA",
      length: "medium",
      content_types: ["video", "carousel", "text post"],
      optimization_notes: ["Native video outperforms links", "Ask questions to boost engagement", "Post in groups for organic reach"],
    },
    email: {
      tone: "personal",
      structure: "subject → preview → story → CTA",
      length: "medium",
      content_types: ["newsletter", "promotional", "transactional"],
      optimization_notes: ["Personalize subject lines", "Single CTA per email", "Keep above-fold content < 200px"],
    },
  },
  insights: [
    "Audience responds best to data-driven claims",
    "Social proof increases conversion by 20-30%",
    "Short-form video is highest engagement format",
  ],
};

export function createPersona(name: string, overrides: Partial<BrandProfile> = {}): PersonaProfile {
  return {
    ...defaultPersona,
    ...overrides,
    name,
    created_at: new Date().toISOString(),
    updated_at: new Date().toISOString(),
  };
}

export function adaptPersonaForPlatform(persona: PersonaProfile, platform: string): PlatformPersona {
  return persona.platforms[platform] || {
    tone: persona.voice.formal_casual > 6 ? "professional" : "casual",
    structure: "hook → content → CTA",
    length: "medium",
    content_types: ["text", "image"],
    optimization_notes: ["Optimize for platform-specific best practices"],
  };
}

export function validatePersona(persona: Partial<PersonaProfile>): { valid: boolean; errors: string[] } {
  const errors: string[] = [];
  if (!persona.name) errors.push("Brand name is required");
  if (!persona.value_props?.length) errors.push("At least one value proposition is required");
  if (!persona.audience) errors.push("Target audience description is required");
  if (persona.voice) {
    if (persona.voice.formal_casual < 1 || persona.voice.formal_casual > 10) errors.push("Voice formal_casual must be 1-10");
    if (persona.voice.bold_subtle < 1 || persona.voice.bold_subtle > 10) errors.push("Voice bold_subtle must be 1-10");
    if (persona.voice.rational_emotional < 1 || persona.voice.rational_emotional > 10) errors.push("Voice rational_emotional must be 1-10");
  }
  return { valid: errors.length === 0, errors };
}

