input.content:
export interface ContentPiece {
  id: string;
  type: "blog" | "social" | "email" | "ad" | "landing" | "video_script" | "podcast";
  title: string;
  body: string;
  meta_title?: string;
  meta_description?: string;
  keywords: string[];
  outline: string[];
  word_count: number;
  readability_score: number;
  seo_score: number;
  status: "draft" | "review" | "published";
}

export interface SEOAnalysis {
  url: string;
  health_score: number;
  issues: Array<{ severity: "critical" | "high" | "medium" | "low"; title: string; description: string; fix: string }>;
  keywords: Array<{ term: string; position?: number; volume?: number; difficulty?: number }>;
  backlinks: number;
  domain_authority: number;
  technical: {
    has_ssl: boolean;
    has_sitemap: boolean;
    has_robots: boolean;
    has_structured_data: boolean;
    mobile_friendly: boolean;
    page_speed: number;
  };
}

export async function generateContentOutline(topic: string, type: ContentPiece["type"], keywords: string[] = []): Promise<ContentPiece> {
  const outlines: Record<string, string[]> = {
    blog: [
      `Introduction: Why ${topic} matters now`,
      "The current landscape and common misconceptions",
      `Step-by-step framework for ${topic}`,
      "Case study or real-world example",
      "Tools and resources",
      "Conclusion and next steps",
      "Call to action",
    ],
    video_script: [
      "Hook (first 3 seconds)",
      "Problem statement",
      "Solution overview",
      "Demo or example",
      "Social proof",
      "Call to action",
    ],
    landing: [
      "Hero section with headline and subhead",
      "Pain point agitation",
      "Solution presentation",
      "Social proof section",
      "Features / benefits",
      "Pricing or offer",
      "FAQ",
      "Final CTA",
    ],
    email: [
      "Subject line and preview text",
      "Greeting",
      "Hook / opening story",
      "Value delivery",
      "Soft CTA",
      "P.S. with urgency",
    ],
  };

  const outline = outlines[type] || outlines.blog;
  const wordCount = type === "blog" ? 1500 : type === "video_script" ? 800 : type === "landing" ? 600 : 400;

  return {
    id: `content_${Date.now()}`,
    type,
    title: `The Complete Guide to ${topic}`,
    body: "",
    meta_title: `${topic} — Complete Guide`,
    meta_description: `Learn everything about ${topic} with our comprehensive guide.`,
    keywords,
    outline,
    word_count: wordCount,
    readability_score: 72,
    seo_score: 68,
    status: "draft",
  };
}

export async function analyzeSEO(url: string): Promise<SEOAnalysis> {
  const issues = [
    { severity: "high" as const, title: "Missing meta description", description: "No meta description tag found on the page.", fix: "Add a compelling 150-160 character meta description." },
    { severity: "medium" as const, title: "Image alt tags missing", description: "Several images lack alt text.", fix: "Add descriptive alt text to all meaningful images." },
    { severity: "low" as const, title: "Heading hierarchy", description: "Multiple H1 tags detected.", fix: "Use exactly one H1 per page." },
    { severity: "critical" as const, title: "Slow page speed", description: "LCP exceeds 2.5s.", fix: "Compress images, enable caching, reduce JS bundle size." },
    { severity: "medium" as const, title: "Missing structured data", description: "No schema.org markup found.", fix: "Add Organization or Product schema." },
  ];

  return {
    url,
    health_score: 58,
    issues,
    keywords: [
      { term: "marketing automation", volume: 10000, difficulty: 65 },
      { term: "marketing hub", volume: 5000, difficulty: 45 },
      { term: "ai marketing", volume: 8000, difficulty: 70 },
    ],
    backlinks: 1240,
    domain_authority: 42,
    technical: {
      has_ssl: true,
      has_sitemap: true,
      has_robots: true,
      has_structured_data: false,
      mobile_friendly: true,
      page_speed: 45,
    },
  };
}

export function expandKeywords(seed: string): string[] {
  const expansions: Record<string, string[]> = {
    "marketing automation": ["marketing automation software", "marketing automation tools", "best marketing automation platforms", "marketing automation for small business", "what is marketing automation"],
    "seo": ["seo tools", "seo audit", "seo strategy", "technical seo", "local seo", "seo keywords"],
    "social media": ["social media management", "social media marketing", "social media scheduling", "social media analytics", "social media strategy"],
  };
  const key = Object.keys(expansions).find(k => seed.toLowerCase().includes(k)) || seed;
  return expansions[key] || [seed, `${seed} tools`, `${seed} strategy`, `${seed} for beginners`, `best ${seed}`];
}

