import { NextResponse } from "next/server";
import { generateCopy, generateEmailSequence, generateSocialCalendar, generateCompetitorIntel, analyzeLanding, analyzeFunnel, analyzeBrand, generateContentOutline, analyzeSEO, expandKeywords } from "@/lib/marketing-engine/skills/marketing-skills";

type Skill =
  | "copy"
  | "emails"
  | "social"
  | "competitors"
  | "landing"
  | "funnel"
  | "brand"
  | "content"
  | "seo"
  | "keywords";

export async function POST(request: Request) {
  try {
    const body = await request.json();
    const { skill, input } = body;

    if (!skill || !input) {
      return NextResponse.json({ error: "skill and input are required" }, { status: 400 });
    }

    let result: unknown;
    switch (skill) {
      case "copy":
        result = await generateCopy(input);
        break;
      case "emails":
        result = await generateEmailSequence(input);
        break;
      case "social":
        result = await generateSocialCalendar(input);
        break;
      case "competitors":
        result = await generateCompetitorIntel(input);
        break;
      case "landing":
        result = await analyzeLanding(input.url);
        break;
      case "funnel":
        result = await analyzeFunnel(input.url);
        break;
      case "brand":
        result = await analyzeBrand(input.url);
        break;
      case "content":
        result = await generateContentOutline(input.topic, input.type, input.keywords);
        break;
      case "seo":
        result = await analyzeSEO(input.url);
        break;
      case "keywords":
        result = expandKeywords(input.seed);
        break;
      default:
        return NextResponse.json({ error: `Unknown skill: ${skill}` }, { status: 400 });
    }

    return NextResponse.json({ skill, result });
  } catch (error) {
    console.error("Skill error:", error);
    return NextResponse.json({ error: "Skill execution failed" }, { status: 500 });
  }
}

