import { NextResponse } from "next/server";
import { createPersona, validatePersona } from "@/lib/marketing-engine/persona";

export async function POST(request: Request) {
  try {
    const body = await request.json();
    const { name, voice, audience, value_props, differentiators, descriptors } = body;

    const validation = validatePersona({ name, voice, audience, value_props, differentiators });
    if (!validation.valid) {
      return NextResponse.json({ error: validation.errors }, { status: 400 });
    }

    const persona = createPersona(name, { voice, audience, value_props, differentiators, descriptors });
    return NextResponse.json(persona);
  } catch (error) {
    console.error("Persona error:", error);
    return NextResponse.json({ error: "Persona creation failed" }, { status: 500 });
  }
}

