"use client";

import { useState } from "react";
import { Card } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import type { AdsHealthReport } from "@/lib/marketing-engine/types";

const PLATFORM_LABELS: Record<string, string> = {
  google: "Google Ads",
  meta: "Meta Ads",
  linkedin: "LinkedIn",
  tiktok: "TikTok",
  microsoft: "Microsoft",
  apple: "Apple Ads",
  amazon: "Amazon Ads",
  cross: "Cross-Platform",
};

const GRADE_COLORS: Record<string, string> = {
  A: "bg-green-100 text-green-800 border-green-200",
  B: "bg-blue-100 text-blue-800 border-blue-200",
  C: "bg-yellow-100 text-yellow-800 border-yellow-200",
  D: "bg-orange-100 text-orange-800 border-orange-200",
  F: "bg-red-100 text-red-800 border-red-200",
};

export function AuditDashboard() {
  const [loading, setLoading] = useState(false);
  const [report, setReport] = useState<AdsHealthReport | null>(null);
  const [selectedPlatforms, setSelectedPlatforms] = useState<string[]>(["google", "meta"]);

  const platforms = [
    { id: "google", label: "Google Ads" },
    { id: "meta", label: "Meta Ads" },
    { id: "linkedin", label: "LinkedIn" },
    { id: "tiktok", label: "TikTok" },
    { id: "microsoft", label: "Microsoft" },
    { id: "apple", label: "Apple Ads" },
    { id: "amazon", label: "Amazon Ads" },
  ];

  const togglePlatform = (id: string) => {
    setSelectedPlatforms(prev =>
      prev.includes(id) ? prev.filter(p => p !== id) : [...prev, id]
    );
  };

  const runAudit = async () => {
    setLoading(true);
    try {
      const res = await fetch("/api/marketing/audit", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          platforms: selectedPlatforms,
          businessType: "agency",
          monthlySpend: 10000,
          data: {
            google: { hasPixel: true, hasGTM: true, hasNegatives: true, hasBrandCampaign: true, avgCTR: 2.5, hasPMax: true, aiMaxEnabled: true, hasSearchTerms: true, hasCallExtensions: true, budgetSufficient: true, hasGA4: true, hasConsentMode: false },
            meta: { hasPixel: true, hasCAPI: true, emqScore: 7.5, creativeCount: 8, hasASC: true, ctrDecline: 15, frequency: 2.1, hasAudiences: true, inLearningPhase: false, budgetMultiplier: 6 },
            linkedin: { hasInsightTag: true, hasConversions: true, formFields: 5, crmSynced: true, msgFrequency: 1, hasABM: true, ctr: 0.6 },
            tiktok: { hasPixel: true, hasEventsAPI: true, creativeCount: 6, isVertical: true, hasHook: true, budgetMultiplier: 60, ctr: 1.2, hasSparkAds: true, watchTime: 7, safeZone: true },
            microsoft: { hasUET: true, hasLinkedInTargeting: true, hasImport: true, importValid: true, ctr: 0.8, budgetSufficient: true },
            apple: { hasSKAN: true, hasAdAttributionKit: true, cppConfigured: true, hasSearchMatches: true },
            amazon: { hasSponsoredProducts: true, hasSponsoredBrands: true, hasSponsoredDisplay: true, acosTarget: 25, tacoTarget: 12, hasProductTargeting: true },
            cross: { hasConsentMode: false, creativeRefresh: true, trackingAudited: true },
          },
        }),
      });
      const data = await res.json();
      setReport(data);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-6">
      <Card className="p-6">
        <h2 className="text-xl font-bold mb-4">Multi-Platform Ads Audit</h2>
        <div className="flex flex-wrap gap-2 mb-4">
          {platforms.map(p => (
            <button
              key={p.id}
              onClick={() => togglePlatform(p.id)}
              className={`px-3 py-1.5 rounded-full text-sm border transition-colors ${
                selectedPlatforms.includes(p.id)
                  ? "bg-indigo-600 text-white border-indigo-600"
                  : "bg-white text-gray-700 border-gray-300 hover:border-indigo-400"
              }`}
            >
              {p.label}
            </button>
          ))}
        </div>
        <Button onClick={runAudit} disabled={loading || selectedPlatforms.length === 0}>
          {loading ? "Running audit..." : "Run Audit"}
        </Button>
      </Card>

      {report && (
        <>
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
            <Card className="p-4 text-center">
              <div className="text-3xl font-bold">{report.ads_health_score}</div>
              <div className="text-sm text-gray-500">Health Score</div>
            </Card>
            <Card className="p-4 text-center">
              <div className={`inline-block px-3 py-1 rounded-full text-sm font-bold border ${GRADE_COLORS[report.grade]}`}>
                Grade {report.grade}
              </div>
              <div className="text-sm text-gray-500 mt-1">Overall Grade</div>
            </Card>
            <Card className="p-4 text-center">
              <div className="text-3xl font-bold">{Object.keys(report.platforms).length}</div>
              <div className="text-sm text-gray-500">Platforms</div>
            </Card>
            <Card className="p-4 text-center">
              <div className="text-3xl font-bold">{report.top_findings.length}</div>
              <div className="text-sm text-gray-500">Findings</div>
            </Card>
          </div>

          <Card className="p-6">
            <h3 className="text-lg font-semibold mb-4">Platform Scores</h3>
            <div className="space-y-3">
              {Object.entries(report.platforms).map(([platform, score]: [string, typeof report.platforms.google]) => (
                <div key={platform} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                  <div>
                    <div className="font-medium">{PLATFORM_LABELS[platform] || platform}</div>
                    <div className="text-sm text-gray-500">{score.checks_run} checks · {score.critical} critical · {score.high} high</div>
                  </div>
                  <div className="flex items-center gap-2">
                    <div className="text-sm font-medium">{score.score}/100</div>
                    <Badge className={GRADE_COLORS[score.grade]}>{score.grade}</Badge>
                  </div>
                </div>
              ))}
            </div>
          </Card>

          <Card className="p-6">
            <h3 className="text-lg font-semibold mb-4">Quick Wins</h3>
            <ul className="space-y-2">
              {report.quick_wins.map((win, i) => (
                <li key={i} className="flex items-start gap-2 text-sm">
                  <span className="text-green-600 mt-0.5">✓</span>
                  <span>{win}</span>
                </li>
              ))}
            </ul>
          </Card>

          <Card className="p-6">
            <h3 className="text-lg font-semibold mb-4">Top Findings</h3>
            <div className="space-y-3">
              {report.top_findings.map((finding, i) => (
                <div key={i} className="border-l-4 border-red-400 pl-4 py-2">
                  <div className="flex items-center gap-2 mb-1">
                    <Badge variant="destructive" className="text-xs">{finding.severity}</Badge>
                    <span className="text-xs text-gray-500">{finding.platform}</span>
                    <span className="text-xs font-mono text-gray-400">{finding.id}</span>
                  </div>
                  <div className="font-medium text-sm">{finding.title}</div>
                  {finding.impact && <div className="text-sm text-gray-600 mt-1">{finding.impact}</div>}
                  {finding.action && <div className="text-sm text-indigo-600 mt-1">→ {finding.action}</div>}
                </div>
              ))}
            </div>
          </Card>

          {report.budget_rec && (
            <Card className="p-6">
              <h3 className="text-lg font-semibold mb-2">Budget Recommendation</h3>
              <div className="text-sm text-gray-600 mb-3">{report.budget_rec.rationale}</div>
              <div className="flex flex-wrap gap-2">
                {Object.entries(report.budget_rec.allocation).map(([channel, amount]) => (
                  <Badge key={channel} variant="outline">{channel}: ${amount.toLocaleString()}/mo</Badge>
                ))}
              </div>
            </Card>
          )}
        </>
      )}
    </div>
  );
}

"use client";

import { useState } from "react";
import { Card } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { generateCopy, generateEmailSequence, generateSocialCalendar, generateCompetitorIntel, analyzeLanding, analyzeFunnel, analyzeBrand, generateContentOutline, analyzeSEO, expandKeywords } from "@/lib/marketing-engine/skills/marketing-skills";
import type { BrandProfile } from "@/lib/marketing-engine/types";

const SKILLS = [
  { id: "copy", label: "Ad Copy", desc: "Platform-optimized headlines and copy", icon: "✍️" },
  { id: "emails", label: "Email Sequences", desc: "Multi-step nurture sequences", icon: "📧" },
  { id: "social", label: "Social Calendar", desc: "30-day content calendar", icon: "📅" },
  { id: "competitors", label: "Competitor Intel", desc: "Competitive deep-dive", icon: "🔍" },
  { id: "landing", label: "Landing Analysis", desc: "CRO and page quality", icon: "🎯" },
  { id: "funnel", label: "Funnel Analysis", desc: "Stage-by-stage dropoff", icon: "📊" },
  { id: "brand", label: "Brand Voice", desc: "Voice analysis and guidelines", icon: "🎨" },
  { id: "content", label: "Content Outline", desc: "Blog/video/landing outlines", icon: "📝" },
  { id: "seo", label: "SEO Audit", desc: "Technical + content SEO", icon: "🔎" },
  { id: "keywords", label: "Keywords", desc: "Keyword expansion", icon: "🔑" },
] as const;

type SkillId = typeof SKILLS[number]["id"];

export function SkillsPanel() {
  const [activeSkill, setActiveSkill] = useState<SkillId | null>(null);
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<unknown>(null);
  const [brand, setBrand] = useState<BrandProfile>({
    name: "Acme Corp",
    voice: { formal_casual: 5, bold_subtle: 7, rational_emotional: 4 },
    descriptors: ["direct", "bold"],
    audience: "SaaS founders",
    value_props: ["Ship faster", "Reduce churn"],
    differentiators: ["AI-native", "No-code setup"],
  });

  const runSkill = async (skill: SkillId) => {
    setLoading(true);
    setActiveSkill(skill);
    setResult(null);
    try {
      const payload: Record<string, unknown> = { brand };
      switch (skill) {
        case "copy":
          payload.platform = "google";
          payload.objective = "lead_generation";
          payload.count = 5;
          break;
        case "emails":
          payload.topic = "onboarding";
          payload.segment = "new_signups";
          payload.length = 5;
          break;
        case "social":
          payload.platforms = ["twitter", "linkedin", "facebook"];
          payload.days = 7;
          break;
        case "competitors":
          payload.competitors = ["competitor1", "competitor2"];
          break;
        case "landing":
          payload.url = "https://example.com";
          break;
        case "funnel":
          payload.url = "https://example.com";
          break;
        case "brand":
          payload.url = "https://example.com";
          break;
        case "content":
          payload.topic = "marketing automation";
          payload.type = "blog";
          payload.keywords = ["automation", "marketing"];
          break;
        case "seo":
          payload.url = "https://example.com";
          break;
        case "keywords":
          payload.seed = "marketing automation";
          break;
      }
      const res = await fetch("/api/marketing/skills", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ skill, input: payload }),
      });
      const data = await res.json();
      setResult(data.result);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
      <Card className="p-6 lg:col-span-1">
        <h2 className="text-xl font-bold mb-4">Marketing Skills</h2>
        <div className="space-y-2">
          {SKILLS.map(skill => (
            <button
              key={skill.id}
              onClick={() => runSkill(skill.id)}
              disabled={loading}
              className={`w-full text-left p-3 rounded-lg border transition-colors ${
                activeSkill === skill.id
                  ? "border-indigo-500 bg-indigo-50"
                  : "border-gray-200 hover:border-indigo-300"
              }`}
            >
              <div className="flex items-center gap-2">
                <span>{skill.icon}</span>
                <span className="font-medium text-sm">{skill.label}</span>
              </div>
              <div className="text-xs text-gray-500 mt-1">{skill.desc}</div>
            </button>
          ))}
        </div>
      </Card>

      <Card className="p-6 lg:col-span-2">
        <h3 className="text-lg font-semibold mb-4">
          {activeSkill ? `${SKILLS.find(s => s.id === activeSkill)?.label} Result` : "Select a skill"}
        </h3>
        {loading && <div className="text-sm text-gray-500">Running...</div>}
        {result && (
          <div className="bg-gray-50 rounded-lg p-4 overflow-auto max-h-96">
            <pre className="text-xs whitespace-pre-wrap font-mono">{JSON.stringify(result, null, 2)}</pre>
          </div>
        )}
        {!activeSkill && !loading && (
          <div className="text-sm text-gray-400">Choose a marketing skill from the left panel to run it against your brand profile.</div>
        )}
      </Card>
    </div>
  );
}

