"use client";

import { useState } from "react";
import { Card } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import { createPersona, validatePersona, adaptPersonaForPlatform } from "@/lib/marketing-engine/persona";
import type { PersonaProfile } from "@/lib/marketing-engine/persona";

export function PersonaBuilder() {
  const [name, setName] = useState("");
  const [audience, setAudience] = useState("");
  const [valueProps, setValueProps] = useState("");
  const [differentiators, setDifferentiators] = useState("");
  const [descriptors, setDescriptors] = useState("");
  const [formalCasual, setFormalCasual] = useState(5);
  const [boldSubtle, setBoldSubtle] = useState(5);
  const [rationalEmotional, setRationalEmotional] = useState(5);
  const [persona, setPersona] = useState<PersonaProfile | null>(null);
  const [selectedPlatform, setSelectedPlatform] = useState("linkedin");
  const [error, setError] = useState<string | null>(null);

  const handleCreate = () => {
    const validation = validatePersona({
      name,
      audience,
      value_props: valueProps.split("\n").filter(Boolean),
      differentiators: differentiators.split("\n").filter(Boolean),
      voice: { formal_casual: formalCasual, bold_subtle: boldSubtle, rational_emotional: rationalEmotional },
    });
    if (!validation.valid) {
      setError(validation.errors.join(", "));
      return;
    }
    setError(null);
    const p = createPersona(name, {
      audience,
      value_props: valueProps.split("\n").filter(Boolean),
      differentiators: differentiators.split("\n").filter(Boolean),
      descriptors: descriptors.split(",").map(s => s.trim()).filter(Boolean),
      voice: { formal_casual: formalCasual, bold_subtle: boldSubtle, rational_emotional: rationalEmotional },
    });
    setPersona(p);
  };

  const platformAdaptation = persona ? adaptPersonaForPlatform(persona, selectedPlatform) : null;

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
      <Card className="p-6 space-y-4">
        <h2 className="text-xl font-bold">Brand Persona Builder</h2>
        <div>
          <label className="block text-sm font-medium mb-1">Brand Name</label>
          <Input value={name} onChange={e => setName(e.target.value)} placeholder="Acme Corp" />
        </div>
        <div>
          <label className="block text-sm font-medium mb-1">Target Audience</label>
          <Input value={audience} onChange={e => setAudience(e.target.value)} placeholder="SaaS founders, 30-50" />
        </div>
        <div>
          <label className="block text-sm font-medium mb-1">Value Propositions (one per line)</label>
          <Textarea value={valueProps} onChange={e => setValueProps(e.target.value)} rows={3} placeholder="Ship faster\nReduce churn" />
        </div>
        <div>
          <label className="block text-sm font-medium mb-1">Differentiators (one per line)</label>
          <Textarea value={differentiators} onChange={e => setDifferentiators(e.target.value)} rows={3} placeholder="AI-native\nNo-code setup" />
        </div>
        <div>
          <label className="block text-sm font-medium mb-1">Descriptors (comma-separated)</label>
          <Input value={descriptors} onChange={e => setDescriptors(e.target.value)} placeholder="direct, bold, clear" />
        </div>
        <div className="space-y-3">
          <div>
            <label className="block text-sm font-medium mb-1">Formal → Casual: {formalCasual}</label>
            <input type="range" min="1" max="10" value={formalCasual} onChange={e => setFormalCasual(Number(e.target.value))} className="w-full" />
          </div>
          <div>
            <label className="block text-sm font-medium mb-1">Bold → Subtle: {boldSubtle}</label>
            <input type="range" min="1" max="10" value={boldSubtle} onChange={e => setBoldSubtle(Number(e.target.value))} className="w-full" />
          </div>
          <div>
            <label className="block text-sm font-medium mb-1">Rational → Emotional: {rationalEmotional}</label>
            <input type="range" min="1" max="10" value={rationalEmotional} onChange={e => setRationalEmotional(Number(e.target.value))} className="w-full" />
          </div>
        </div>
        {error && <div className="text-sm text-red-600">{error}</div>}
        <Button onClick={handleCreate} className="w-full">Create Persona</Button>
      </Card>

      <Card className="p-6 space-y-4">
        <h2 className="text-xl font-bold">Persona Output</h2>
        {!persona && (
          <div className="text-sm text-gray-400">Fill out the form and create a persona to see platform adaptations.</div>
        )}
        {persona && (
          <>
            <div className="space-y-2">
              <div className="font-semibold">{persona.name}</div>
              <div className="text-sm text-gray-600">{persona.audience}</div>
              <div className="flex flex-wrap gap-1">
                {persona.descriptors.map(d => <Badge key={d} variant="outline">{d}</Badge>)}
              </div>
              <div className="text-sm">
                <span className="font-medium">Voice:</span> Formal {formalCasular = formalCasual}, Bold {boldSubtle}, Emotional {rationalEmotional}
              </div>
            </div>
            <div>
              <label className="block text-sm font-medium mb-2">Platform Adaptation</label>
              <select
                value={selectedPlatform}
                onChange={e => setSelectedPlatform(e.target.value)}
                className="w-full p-2 border rounded-md text-sm"
              >
                <option value="linkedin">LinkedIn</option>
                <option value="twitter">Twitter / X</option>
                <option value="facebook">Facebook</option>
                <option value="email">Email</option>
              </select>
            </div>
            {platformAdaptation && (
              <div className="bg-gray-50 rounded-lg p-4 space-y-2 text-sm">
                <div><span className="font-medium">Tone:</span> {platformAdaptation.tone}</div>
                <div><span className="font-medium">Structure:</span> {platformAdaptation.structure}</div>
                <div><span className="font-medium">Length:</span> {platformAdaptation.length}</div>
                <div><span className="font-medium">Content types:</span> {platformAdaptation.content_types.join(", ")}</div>
                <div>
                  <span className="font-medium">Optimization notes:</span>
                  <ul className="list-disc ml-4 mt-1">
                    {platformAdaptation.optimization_notes.map((n, i) => <li key={i}>{n}</li>)}
                  </ul>
                </div>
              </div>
            )}
          </>
        )}
      </Card>
    </div>
  );
}

