export function Badge({ className = "", children, variant = "default", ...props }: React.HTMLAttributes<HTMLSpanElement> & { variant?: "default" | "outline" | "destructive" | "secondary" }) {
  const variants: Record<string, string> = {
    default: "bg-indigo-100 text-indigo-800 border-indigo-200",
    outline: "bg-transparent text-gray-700 border-gray-300",
    destructive: "bg-red-100 text-red-800 border-red-200",
    secondary: "bg-gray-100 text-gray-800 border-gray-200",
  };
  return (
    <span
      className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium border ${variants[variant] || variants.default} ${className}`}
      {...props}
    >
      {children}
    </span>
  );
}

