"use client";

import React from "react";

export function Card({ className = "", children, ...props }: React.HTMLAttributes<HTMLDivElement>) {
  return (
    <div className={`bg-white rounded-lg border border-gray-200 shadow-sm ${className}`} {...props}>
      {children}
    </div>
  );
}

export function Button({ className = "", children, variant = "default", ...props }: React.ButtonHTMLAttributes<HTMLButtonElement> & { variant?: "default" | "outline" | "ghost" | "destructive" | "secondary" }) {
  const variants: Record<string, string> = {
    default: "bg-indigo-600 text-white hover:bg-indigo-700",
    outline: "border border-gray-300 bg-transparent hover:bg-gray-50",
    ghost: "hover:bg-gray-100",
    destructive: "bg-red-600 text-white hover:bg-red-700",
    secondary: "bg-gray-100 text-gray-900 hover:bg-gray-200",
  };
  return (
    <button className={`inline-flex items-center justify-center rounded-md text-sm font-medium transition-colors disabled:pointer-events-none disabled:opacity-50 h-9 px-4 py-2 ${variants[variant] || variants.default} ${className}`} {...props}>
      {children}
    </button>
  );
}

export function Input({ className = "", invalid, ...props }: React.InputHTMLAttributes<HTMLInputElement> & { invalid?: boolean }) {
  return (
    <input
      className={`flex h-9 w-full rounded-md border ${invalid ? "border-red-500" : "border-gray-300"} bg-white px-3 py-1 text-sm placeholder:text-gray-400 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent disabled:cursor-not-allowed disabled:opacity-50 ${className}`}
      {...props}
    />
  );
}

export function Textarea({ className = "", ...props }: React.TextareaHTMLAttributes<HTMLTextAreaElement>) {
  return (
    <textarea
      className={`flex min-h-[80px] w-full rounded-md border border-gray-300 bg-white px-3 py-2 text-sm placeholder:text-gray-400 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent disabled:cursor-not-allowed disabled:opacity-50 ${className}`}
      {...props}
    />
  );
}

export function Badge({ className = "", children, variant = "default", ...props }: React.HTMLAttributes<HTMLSpanElement> & { variant?: "default" | "outline" | "destructive" | "secondary" }) {
  const variants: Record<string, string> = {
    default: "bg-indigo-100 text-indigo-800 border-indigo-200",
    outline: "bg-transparent text-gray-700 border-gray-300",
    destructive: "bg-red-100 text-red-800 border-red-200",
    secondary: "bg-gray-100 text-gray-800 border-gray-200",
  };
  return (
    <span
      className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium border ${variants[variant] || variants.default} ${className}`}
      {...props}
    >
      {children}
    </span>
  );
}

export function Tabs({ children, defaultValue, value, onValueChange }: {
  children: React.ReactNode;
  defaultValue?: string;
  value?: string;
  onValueChange?: (v: string) => void;
}) {
  const [internal, setInternal] = React.useState(defaultValue || "");
  const current = value ?? internal;
  return (
    <div data-value={current}>
      {React.Children.map(children, child => {
        if (React.isValidElement(child)) {
          return React.cloneElement(child as React.ReactElement<{ value?: string }>, {
            current,
            onSelect: (v: string) => { onValueChange?.(v); setInternal(v); },
          });
        }
        return child;
      })}
    </div>
  );
}

export function TabsList({ children, className = "" }: { children: React.ReactNode; className?: string }) {
  return (
    <div className={`inline-flex items-center gap-1 p-1 bg-gray-100 rounded-lg ${className}`}>
      {children}
    </div>
  );
}

export function TabsTrigger({ children, value, current, onSelect }: {
  children: React.ReactNode;
  value?: string;
  current?: string;
  onSelect?: (v: string) => void;
}) {
  const active = current === value;
  return (
    <button
      onClick={() => onSelect?.(value || "")}
      className={`px-3 py-1.5 text-sm font-medium rounded-md transition-colors ${
        active ? "bg-white text-gray-900 shadow-sm" : "text-gray-600 hover:text-gray-900"
      }`}
    >
      {children}
    </button>
  );
}

export function TabsContent({ children, value, current }: {
  children: React.ReactNode;
  value?: string;
  current?: string;
}) {
  if (current !== value) return null;
  return <div>{children}</div>;
}

export function Select({ children, value, onValueChange }: {
  children: React.ReactNode;
  value?: string;
  onValueChange?: (v: string) => void;
}) {
  return (
    <div className="relative">
      <select
        value={value}
        onChange={e => onValueChange?.(e.target.value)}
        className="flex h-9 w-full items-center justify-between rounded-md border border-gray-300 bg-white px-3 py-2 text-sm placeholder:text-gray-400 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent disabled:cursor-not-allowed disabled:opacity-50"
      >
        {children}
      </select>
    </div>
  );
}

export function SelectItem({ children, value }: { children: React.ReactNode; value?: string }) {
  return <option value={value}>{children}</option>;
}

export function Slider({ value, onValueChange, min = 0, max = 100, step = 1 }: {
  value: number;
  onValueChange?: (v: number) => void;
  min?: number;
  max?: number;
  step?: number;
}) {
  return (
    <input
      type="range"
      min={min}
      max={max}
      step={step}
      value={value}
      onChange={e => onValueChange?.(Number(e.target.value))}
      className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-indigo-600"
    />
  );
}

