export function Tabs({ children, defaultValue, value, onValueChange, className = "" }: {
  children: React.ReactNode;
  defaultValue?: string;
  value?: string;
  onValueChange?: (v: string) => void;
  className?: string;
}) {
  const [internal, setInternal] = React.useState(defaultValue || "");
  const current = value ?? internal;
  return (
    <div data-value={current} className={className}>
      {React.Children.map(children, child => {
        if (!React.isValidElement(child)) return child;
        const childProps = (child.props || {}) as Record<string, unknown>;
        if (typeof childProps.onSelect === "function") {
          return React.cloneElement(child, {
            ...childProps,
            current,
            onSelect: (v: string) => { (childProps.onSelect as (v: string) => void)(v); onValueChange?.(v); setInternal(v); },
          });
        }
        return child;
      })}
    </div>
  );
}

