import { glmChat, isGLMAvailable, type GLMMessage } from "@/lib/glm";

export interface AIGenerateOptions {
  prompt: string;
  systemPrompt?: string;
  temperature?: number;
  maxTokens?: number;
  model?: string;
}

export async function aiGenerate(options: AIGenerateOptions): Promise<{ text: string; model: string; tokens: number; error?: string }> {
  if (!isGLMAvailable()) {
    return { text: "", model: "none", tokens: 0, error: "GLM_API_KEY not configured" };
  }

  const messages: GLMMessage[] = [
    { role: "system", content: options.systemPrompt || "You are a world-class marketing copywriter and strategist. Output only the requested content, no explanations." },
    { role: "user", content: options.prompt },
  ];

  const result = await glmChat(messages, {
    model: options.model || "glm-4-flash",
    temperature: options.temperature ?? 0.7,
    maxTokens: options.maxTokens ?? 2048,
  });

  if (!result.ok) {
    return { text: "", model: result.model, tokens: 0, error: result.error };
  }

  return { text: result.content, model: result.model, tokens: result.tokens };
}

export async function generateAdCopy(brief: {
  brand: { name: string; value_props: string[]; differentiators: string[]; descriptors: string[] };
  platform: string;
  objective: string;
  count?: number;
}): Promise<string[]> {
  const count = brief.count || 5;
  const prompt = `Generate ${count} ${brief.platform} ad headlines for ${brief.brand.name}.
Brand value props: ${brief.brand.value_props.join(", ")}
Differentiators: ${brief.brand.differentiators.join(", ")}
Descriptors: ${brief.brand.descriptors.join(", ")}
Objective: ${brief.objective}

Output exactly ${count} headlines, one per line, no numbering, no quotes, no explanations.`;

  const result = await aiGenerate({ prompt, temperature: 0.8, maxTokens: 512 });
  if (result.error || !result.text) {
    return fallbackCopy(brief);
  }

  return result.text.split("\n").filter(line => line.trim().length > 0).slice(0, count);
}

export async function generateEmailSequence(brief: {
  brand: { name: string; value_props: string[] };
  topic: string;
  segment: string;
  length?: number;
}): Promise<Array<{ day: number; subject: string; body: string; cta: string }>> {
  const length = brief.length || 5;
  const prompt = `Create a ${length}-email nurture sequence for ${brief.brand.name} about "${brief.topic}" targeting ${brief.segment}.
Value props: ${brief.brand.value_props.join(", ")}

Output JSON array only, no explanations:
[{"day": 1, "subject": "...", "body": "...", "cta": "..."}, ...]`;

  const result = await aiGenerate({ prompt, temperature: 0.7, maxTokens: 2048 });
  if (result.error || !result.text) {
    return fallbackEmailSequence(brief);
  }

  try {
    const cleaned = result.text.replace(/```json\n?|\n?```/g, "").trim();
    const parsed = JSON.parse(cleaned);
    if (Array.isArray(parsed)) return parsed.slice(0, length);
  } catch {}
  return fallbackEmailSequence(brief);
}

export async function generateSocialCalendar(brief: {
  brand: { name: string; value_props: string[] };
  platforms: string[];
  days?: number;
}): Promise<Array<{ date: string; platform: string; hook: string; caption: string; cta: string }>> {
  const days = brief.days || 7;
  const prompt = `Create a ${days}-day social media content calendar for ${brief.brand.name}.
Platforms: ${brief.platforms.join(", ")}
Value props: ${brief.brand.value_props.join(", ")}

Output JSON array only:
[{"date": "YYYY-MM-DD", "platform": "...", "hook": "...", "caption": "...", "cta": "..."}, ...]`;

  const result = await aiGenerate({ prompt, temperature: 0.8, maxTokens: 2048 });
  if (result.error || !result.text) {
    return fallbackSocialCalendar(brief);
  }

  try {
    const cleaned = result.text.replace(/```json\n?|\n?```/g, "").trim();
    const parsed = JSON.parse(cleaned);
    if (Array.isArray(parsed)) return parsed.slice(0, days);
  } catch {}
  return fallbackSocialCalendar(brief);
}

export async function generateCompetitorIntel(brief: {
  brand: { name: string; audience: string; differentiators: string[] };
  competitors: string[];
}): Promise<Array<{ competitor: string; positioning: string; gaps: string[]; opportunities: string[] }>> {
  const prompt = `Analyze these competitors for ${brief.brand.name} (audience: ${brief.brand.audience}, differentiators: ${brief.brand.differentiators.join(", ")}):
${brief.competitors.map(c => `- ${c}`).join("\n")}

For each competitor, provide positioning, gaps, and opportunities.
Output JSON array only:
[{"competitor": "...", "positioning": "...", "gaps": ["..."], "opportunities": ["..."]}, ...]`;

  const result = await aiGenerate({ prompt, temperature: 0.6, maxTokens: 2048 });
  if (result.error || !result.text) {
    return fallbackCompetitorIntel(brief);
  }

  try {
    const cleaned = result.text.replace(/```json\n?|\n?```/g, "").trim();
    const parsed = JSON.parse(cleaned);
    if (Array.isArray(parsed)) return parsed;
  } catch {}
  return fallbackCompetitorIntel(brief);
}

export async function generateContentOutline(brief: { topic: string; type: string; keywords: string[] }): Promise<{ title: string; outline: string[]; meta_title: string; meta_description: string }> {
  const prompt = `Create a detailed content outline for a ${brief.type} about "${brief.topic}".
Keywords to include: ${brief.keywords.join(", ")}

Output JSON only:
{"title": "...", "outline": ["..."], "meta_title": "...", "meta_description": "..."}`;

  const result = await aiGenerate({ prompt, temperature: 0.6, maxTokens: 1024 });
  if (result.error || !result.text) {
    return fallbackContentOutline(brief);
  }

  try {
    const cleaned = result.text.replace(/```json\n?|\n?```/g, "").trim();
    return JSON.parse(cleaned);
  } catch {}
  return fallbackContentOutline(brief);
}

export async function analyzeLandingPage(url: string): Promise<{ score: number; issues: string[]; recommendations: string[] }> {
  const prompt = `Analyze this landing page URL: ${url}
Evaluate: page speed, CTA clarity, trust signals, message match, mobile responsiveness, conversion readiness.
Score 0-100 and list 3-5 specific issues and recommendations.

Output JSON only:
{"score": 0, "issues": ["..."], "recommendations": ["..."]}`;

  const result = await aiGenerate({ prompt, temperature: 0.3, maxTokens: 1024 });
  if (result.error || !result.text) {
    return { score: 50, issues: ["Unable to analyze page"], recommendations: ["Ensure page is accessible"] };
  }

  try {
    const cleaned = result.text.replace(/```json\n?|\n?```/g, "").trim();
    return JSON.parse(cleaned);
  } catch {}
  return { score: 50, issues: ["Parse error"], recommendations: ["Retry analysis"] };
}

export async function analyzeBrandVoice(url: string): Promise<{ voice: { formal_casual: number; bold_subtle: number; rational_emotional: number }; descriptors: string[]; consistency_score: number }> {
  const prompt = `Analyze the brand voice of ${url}.
Rate 1-10 on: formal→casual, bold→subtle, rational→emotional.
List 5 descriptors and a consistency score (0-100).

Output JSON only:
{"voice": {"formal_casual": 5, "bold_subtle": 5, "rational_emotional": 5}, "descriptors": ["..."], "consistency_score": 0}`;

  const result = await aiGenerate({ prompt, temperature: 0.3, maxTokens: 512 });
  if (result.error || !result.text) {
    return { voice: { formal_casual: 5, bold_subtle: 5, rational_emotional: 5 }, descriptors: ["professional"], consistency_score: 50 };
  }

  try {
    const cleaned = result.text.replace(/```json\n?|\n?```/g, "").trim();
    return JSON.parse(cleaned);
  } catch {}
  return { voice: { formal_casual: 5, bold_subtle: 5, rational_emotional: 5 }, descriptors: ["professional"], consistency_score: 50 };
}

function fallbackCopy(brief: { brand: { value_props: string[]; differentiators: string[]; descriptors: string[] }; platform: string; count?: number }): string[] {
  const valProp = brief.brand.value_props[0] || "transform your results";
  const diff = brief.brand.differentiators[0] || "";
  const desc = brief.brand.descriptors[0] || "effortlessly";
  const templates = [
    `${desc} ${valProp} — Start Today`,
    `Stop Struggling With ${valProp}. Try ${diff}.`,
    `${valProp} in Minutes. See How.`,
    `The ${diff} Way to ${valProp}`,
    `${desc} ${valProp} — Rated #1`,
  ];
  return Array.from({ length: brief.count || 5 }, (_, i) => templates[i % templates.length]);
}

function fallbackEmailSequence(brief: { brand: { name: string; value_props: string[] }; topic: string; segment: string; length?: number }): Array<{ day: number; subject: string; body: string; cta: string }> {
  const valProp = brief.brand.value_props[0] || "achieve better results";
  return Array.from({ length: brief.length || 5 }, (_, i) => ({
    day: i + 1,
    subject: i === 0 ? `Welcome to ${brief.brand.name}` : `Day ${i + 1}: ${brief.topic}`,
    body: `Email ${i + 1} about ${brief.topic}. ${brief.brand.name} helps you ${valProp}.`,
    cta: "Learn more",
  }));
}

function fallbackSocialCalendar(brief: { brand: { name: string; value_props: string[] }; platforms: string[]; days?: number }): Array<{ date: string; platform: string; hook: string; caption: string; cta: string }> {
  const valProp = brief.brand.value_props[0] || "better results";
  return Array.from({ length: brief.days || 7 }, (_, i) => ({
    date: new Date(Date.now() + i * 86400000).toISOString().split("T")[0],
    platform: brief.platforms[i % brief.platforms.length],
    hook: `Stop wasting time on ${valProp}`,
    caption: `${valProp} doesn't have to be complicated.`,
    cta: "Learn more",
  }));
}

function fallbackCompetitorIntel(brief: { brand: { name: string; differentiators: string[] }; competitors: string[] }): Array<{ competitor: string; positioning: string; gaps: string[]; opportunities: string[] }> {
  return brief.competitors.map(c => ({
    competitor: c,
    positioning: `Positions as leading solution`,
    gaps: ["Weak social proof", "No clear differentiation"],
    opportunities: [`Emphasize ${brief.brand.differentiators[0] || "unique value"}`],
  }));
}

function fallbackContentOutline(brief: { topic: string; type: string; keywords: string[] }): { title: string; outline: string[]; meta_title: string; meta_description: string } {
  return {
    title: `The Complete Guide to ${brief.topic}`,
    outline: [`Introduction to ${brief.topic}`, "Key concepts", "Step-by-step guide", "Case study", "Conclusion"],
    meta_title: `${brief.topic} — Complete Guide`,
    meta_description: `Learn everything about ${brief.topic}.`,
  };
}

