input.content:
import { NextResponse } from "next/server";
import { db, uid, now } from "@/lib/db";

export interface Campaign {
  id: string;
  workspace_id: string;
  name: string;
  objective: string;
  platform: string;
  status: "draft" | "active" | "paused" | "completed";
  budget_cents: number;
  spent_cents: number;
  start_date: number | null;
  end_date: number | null;
  target_metric: string;
  target_value: number;
  current_value: number;
  created_at: number;
  updated_at: number;
}

export async function GET(request: Request) {
  try {
    const { searchParams } = new URL(request.url);
    const workspace_id = searchParams.get("workspace_id") || "default";
    const status = searchParams.get("status");

    let sql = `SELECT * FROM marketing_campaigns WHERE workspace_id = ?`;
    const args: (string | number)[] = [workspace_id];
    if (status) {
      sql += ` AND status = ?`;
      args.push(status);
    }
    sql += ` ORDER BY created_at DESC`;

    const campaigns = db.prepare(sql).all(...args) as Record<string, unknown>[];
    return NextResponse.json(campaigns);
  } catch (error) {
    console.error("Error fetching campaigns:", error);
    return NextResponse.json({ error: "Failed to fetch campaigns" }, { status: 500 });
  }
}

export async function POST(request: Request) {
  try {
    const body = await request.json();
    const { workspace_id, name, objective, platform, budget_cents, start_date, end_date, target_metric, target_value } = body;

    if (!name || !platform) {
      return NextResponse.json({ error: "name and platform are required" }, { status: 400 });
    }

    const id = uid("camp_");
    const t = now();

    db.prepare(
      `
      INSERT INTO marketing_campaigns (id, workspace_id, name, objective, platform, status, budget_cents, spent_cents, start_date, end_date, target_metric, target_value, current_value, created_at, updated_at)
      VALUES (?, ?, ?, ?, ?, 'draft', ?, 0, ?, ?, ?, ?, 0, ?, ?)
    `,
    ).run(
      id,
      workspace_id || "default",
      name,
      objective || "",
      platform,
      budget_cents || 0,
      start_date || null,
      end_date || null,
      target_metric || "",
      target_value || 0,
      t,
      t,
    );

    const campaign = db.prepare(`SELECT * FROM marketing_campaigns WHERE id = ?`).get(id) as Record<string, unknown> | undefined;
    return NextResponse.json(campaign);
  } catch (error) {
    console.error("Error creating campaign:", error);
    return NextResponse.json({ error: "Failed to create campaign" }, { status: 500 });
  }
}

