"use client";

import { useState, useEffect } from "react";
import { Card } from "@/components/ui";
import { Button } from "@/components/ui";
import { Badge } from "@/components/marketing/ui";
import { Input } from "@/components/ui";
import { Select, SelectItem } from "@/components/marketing/ui";

type Campaign = {
  id: string;
  name: string;
  objective: string;
  platform: string;
  status: "draft" | "active" | "paused" | "completed";
  budget_cents: number;
  spent_cents: number;
  target_metric: string;
  target_value: number;
  current_value: number;
  created_at: number;
};

const STATUS_COLORS: Record<string, string> = {
  draft: "bg-gray-100 text-gray-800",
  active: "bg-green-100 text-green-800",
  paused: "bg-yellow-100 text-yellow-800",
  completed: "bg-blue-100 text-blue-800",
};

export function CampaignManager() {
  const [campaigns, setCampaigns] = useState<Campaign[]>([]);
  const [loading, setLoading] = useState(false);
  const [showForm, setShowForm] = useState(false);
  const [form, setForm] = useState({ name: "", objective: "", platform: "google", budget_cents: 500000, target_metric: "leads", target_value: 100 });

  useEffect(() => {
    fetchCampaigns();
  }, []);

  const fetchCampaigns = async () => {
    try {
      const res = await fetch("/api/marketing/campaigns");
      const data = await res.json();
      setCampaigns(data || []);
    } catch (e) {
      console.error(e);
    }
  };

  const createCampaign = async () => {
    setLoading(true);
    try {
      const res = await fetch("/api/marketing/campaigns", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ ...form, workspace_id: "default" }),
      });
      if (res.ok) {
        setShowForm(false);
        setForm({ name: "", objective: "", platform: "google", budget_cents: 500000, target_metric: "leads", target_value: 100 });
        fetchCampaigns();
      }
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const updateStatus = async (id: string, status: Campaign["status"]) => {
    try {
      await fetch(`/api/marketing/campaigns/${id}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ status }),
      });
      fetchCampaigns();
    } catch (e) {
      console.error(e);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h2 className="text-xl font-bold">Campaigns</h2>
        <Button onClick={() => setShowForm(!showForm)}>{showForm ? "Cancel" : "New Campaign"}</Button>
      </div>

      {showForm && (
        <Card className="p-6 space-y-4">
          <div>
            <label className="block text-sm font-medium mb-1">Campaign Name</label>
            <Input value={form.name} onChange={e => setForm({ ...form, name: e.target.value })} placeholder="Q3 Product Launch" />
          </div>
          <div>
            <label className="block text-sm font-medium mb-1">Objective</label>
            <Input value={form.objective} onChange={e => setForm({ ...form, objective: e.target.value })} placeholder="Lead generation, awareness, etc." />
          </div>
          <div>
            <label className="block text-sm font-medium mb-1">Platform</label>
            <Select value={form.platform} onValueChange={v => setForm({ ...form, platform: v })}>
              <SelectItem value="google">Google Ads</SelectItem>
              <SelectItem value="meta">Meta Ads</SelectItem>
              <SelectItem value="linkedin">LinkedIn</SelectItem>
              <SelectItem value="tiktok">TikTok</SelectItem>
              <SelectItem value="email">Email</SelectItem>
              <SelectItem value="social">Social</SelectItem>
            </Select>
          </div>
          <div>
            <label className="block text-sm font-medium mb-1">Budget ($)</label>
            <Input type="number" value={form.budget_cents / 100} onChange={e => setForm({ ...form, budget_cents: Number(e.target.value) * 100 })} />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium mb-1">Target Metric</label>
              <Select value={form.target_metric} onValueChange={v => setForm({ ...form, target_metric: v })}>
                <SelectItem value="leads">Leads</SelectItem>
                <SelectItem value="sales">Sales</SelectItem>
                <SelectItem value="revenue">Revenue</SelectItem>
                <SelectItem value="installs">Installs</SelectItem>
              </Select>
            </div>
            <div>
              <label className="block text-sm font-medium mb-1">Target Value</label>
              <Input type="number" value={form.target_value} onChange={e => setForm({ ...form, target_value: Number(e.target.value) })} />
            </div>
          </div>
          <Button onClick={createCampaign} disabled={loading || !form.name}>
            {loading ? "Creating..." : "Create Campaign"}
          </Button>
        </Card>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {campaigns.map(campaign => (
          <Card key={campaign.id} className="p-4 space-y-3">
            <div className="flex items-start justify-between">
              <div>
                <h3 className="font-semibold">{campaign.name}</h3>
                <p className="text-sm text-gray-500">{campaign.objective}</p>
              </div>
              <Badge className={STATUS_COLORS[campaign.status]}>{campaign.status}</Badge>
            </div>
            <div className="flex items-center gap-2 text-sm">
              <Badge variant="outline">{campaign.platform}</Badge>
              <span className="text-gray-500">${(campaign.budget_cents / 100).toLocaleString()}</span>
            </div>
            <div className="text-sm">
              <div className="flex justify-between mb-1">
                <span className="text-gray-600">{campaign.target_metric}</span>
                <span className="font-medium">{campaign.current_value} / {campaign.target_value}</span>
              </div>
              <div className="w-full bg-gray-200 rounded-full h-2">
                <div
                  className="bg-indigo-600 h-2 rounded-full transition-all"
                  style={{ width: `${Math.min(100, (campaign.current_value / campaign.target_value) * 100)}%` }}
                />
              </div>
            </div>
            <div className="flex gap-2">
              {campaign.status === "draft" && (
                <Button size="sm" onClick={() => updateStatus(campaign.id, "active")}>Launch</Button>
              )}
              {campaign.status === "active" && (
                <Button size="sm" variant="outline" onClick={() => updateStatus(campaign.id, "paused")}>Pause</Button>
              )}
              {campaign.status === "paused" && (
                <Button size="sm" onClick={() => updateStatus(campaign.id, "active")}>Resume</Button>
              )}
            </div>
          </Card>
        ))}
      </div>

      {campaigns.length === 0 && (
        <Card className="p-8 text-center text-gray-500">
          No campaigns yet. Create your first campaign to get started.
        </Card>
      )}
    </div>
  );
}

