import { NextResponse } from "next/server";
import { db } from "@/lib/db";

export async function PATCH(request: Request, { params }: { params: { id: string } }) {
  try {
    const body = await request.json();
    const { status, name, objective, platform, budget_cents, target_metric, target_value, current_value } = body;

    const allowed = ["draft", "active", "paused", "completed"];
    if (status && !allowed.includes(status)) {
      return NextResponse.json({ error: "Invalid status" }, { status: 400 });
    }

    const sets: string[] = [];
    const args: (string | number)[] = [];
    if (name !== undefined) { sets.push("name = ?"); args.push(name); }
    if (objective !== undefined) { sets.push("objective = ?"); args.push(objective); }
    if (platform !== undefined) { sets.push("platform = ?"); args.push(platform); }
    if (status !== undefined) { sets.push("status = ?"); args.push(status); }
    if (budget_cents !== undefined) { sets.push("budget_cents = ?"); args.push(budget_cents); }
    if (target_metric !== undefined) { sets.push("target_metric = ?"); args.push(target_metric); }
    if (target_value !== undefined) { sets.push("target_value = ?"); args.push(target_value); }
    if (current_value !== undefined) { sets.push("current_value = ?"); args.push(current_value); }

    if (sets.length === 0) {
      return NextResponse.json({ error: "No fields to update" }, { status: 400 });
    }

    sets.push("updated_at = ?");
    args.push(Date.now());
    args.push(params.id);

    db.prepare(`UPDATE marketing_campaigns SET ${sets.join(", ")} WHERE id = ?`).run(...args);
    const campaign = db.prepare(`SELECT * FROM marketing_campaigns WHERE id = ?`).get(params.id) as Record<string, unknown> | undefined;
    return NextResponse.json(campaign);
  } catch (error) {
    console.error("Error updating campaign:", error);
    return NextResponse.json({ error: "Failed to update campaign" }, { status: 500 });
  }
}

export async function DELETE(request: Request, { params }: { params: { id: string } }) {
  try {
    db.prepare(`DELETE FROM marketing_campaigns WHERE id = ?`).run(params.id);
    return NextResponse.json({ success: true });
  } catch (error) {
    console.error("Error deleting campaign:", error);
    return NextResponse.json({ error: "Failed to delete campaign" }, { status: 500 });
  }
}

