+
+type Stat = { label: string; value: string | number; change?: string };
+
+export function MarketingDashboard() {
+  const [stats, setStats] = useState<Stat[]>([]);
+  const [recentCampaigns, setRecentCampaigns] = useState<Campaign[]>([]);
+  const [loading, setLoading] = useState(true);
+
+  useEffect(() => {
+    Promise.all([
+      fetch("/api/marketing/campaigns").then(r => r.json()),
+    ]).then(([campaigns]) => {
+      const c = campaigns || [];
+      setRecentCampaigns(c.slice(0, 5));
+
+      const totalBudget = c.reduce((sum: number, camp: Campaign) => sum + camp.budget_cents, 0);
+      const totalSpent = c.reduce((sum: number, camp: Campaign) => sum + camp.spent_cents, 0);
+      const activeCampaigns = c.filter((camp: Campaign) => camp.status === "active").length;
+      const totalTargetValue = c.reduce((sum: number, camp: Campaign) => sum + camp.target_value, 0);
+      const totalCurrentValue = c.reduce((sum: number, camp: Campaign) => sum + camp.current_value, 0);
+      const progress = totalTargetValue > 0 ? Math.round((totalCurrentValue / totalTargetValue) * 100) : 0;
+
+      setStats([
+        { label: "Total Budget", value: `$${(totalBudget / 100).toLocaleString()}`, change: `${c.length} campaigns` },
+        { label: "Spent", value: `$${(totalSpent / 100).toLocaleString()}`, change: `${Math.round((totalSpent / totalBudget) * 100)}% of budget` },
+        { label: "Active Campaigns", value: activeCampaigns, change: `${c.length - activeCampaigns} paused/draft` },
+        { label: "Target Progress", value: `${progress}%`, change: `${totalCurrentValue} / ${totalTargetValue}` },
+      ]);
+      setLoading(false);
+    }).catch(() => setLoading(false));
+  }, []);
+
+  if (loading) {
+    return (
+      <Card className="p-8 text-center">
+        <div className="text-sm text-gray-500">Loading dashboard...</div>
+      </Card>
+    );
+  }
+
+  return (
+    <div className="space-y-6">
+      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
+        {stats.map((stat, i) => (
+          <Card key={i} className="p-4">
+            <div className="text-sm text-gray-500">{stat.label}</div>
+            <div className="text-2xl font-bold mt-1">{stat.value}</div>
+            <div className="text-xs text-gray-400 mt-1">{stat.change}</div>
+          </Card>
+        ))}
+      </div>
+
+      <Card className="p-6">
+        <h3 className="text-lg font-semibold mb-4">Recent Campaigns</h3>
+        {recentCampaigns.length === 0 ? (
+          <div className="text-sm text-gray-500">No campaigns yet. Create one in the Campaigns tab.</div>
+        ) : (
+          <div className="space-y-3">
+            {recentCampaigns.map(campaign => (
+              <div key={campaign.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
+                <div>
+                  <div className="font-medium">{campaign.name}</div>
+                  <div className="text-sm text-gray-500">{campaign.platform} · {campaign.target_metric}</div>
+                </div>
+                <div className="flex items-center gap-2">
+                  <Badge className={campaign.status === "active" ? "bg-green-100 text-green-800" : "bg-gray-100 text-gray-800"}>
+                    {campaign.status}
+                  </Badge>
+                  <span className="text-sm font-medium">{campaign.current_value}/{campaign.target_value}</span>
+                </div>
+              </div>
+            ))}
+          </div>
+        )}
+      </Card>
+    </div>
+  );
+}

