import { db, uid, now } from "@/lib/db";

export interface EmailList {
  id: string;
  workspace_id: string;
  name: string;
  description?: string;
  subscribers_count: number;
  created_at: number;
  updated_at: number;
}

export interface Subscriber {
  id: string;
  list_id: string;
  email: string;
  first_name?: string;
  last_name?: string;
  phone?: string;
  company?: string;
  tags?: string;
  custom_fields?: string;
  status: "subscribed" | "unsubscribed" | "bounced" | "pending";
  confirmed_at?: number;
  unsubscribed_at?: number;
  last_opened_at?: number;
  last_clicked_at?: number;
  created_at: number;
  updated_at: number;
}

export function createList(input: { name: string; description?: string; workspace_id?: string }): EmailList {
  const id = uid("el_");
  const t = now();
  db.prepare(
    `INSERT INTO email_lists (id, workspace_id, name, description, subscribers_count, created_at, updated_at)
     VALUES (?, ?, ?, ?, 0, ?, ?)`,
  ).run(id, input.workspace_id || "default", input.name, input.description || null, t, t);
  return getList(id)!;
}

export function getList(id: string): EmailList | null {
  const row = db.prepare(`SELECT * FROM email_lists WHERE id = ?`).get(id) as Record<string, unknown> | undefined;
  if (!row) return null;
  return row as EmailList;
}

export function listLists(workspaceId = "default"): EmailList[] {
  return db.prepare(`SELECT * FROM email_lists WHERE workspace_id = ? ORDER BY created_at DESC`).all(workspaceId) as Record<string, unknown>[];
}

export function updateList(id: string, patch: Partial<EmailList>): EmailList | null {
  const cur = getList(id);
  if (!cur) return null;
  const merged = { ...cur, ...patch, updated_at: now() };
  db.prepare(`UPDATE email_lists SET name=?, description=?, updated_at=? WHERE id=?`).run(
    merged.name, merged.description || null, merged.updated_at, id,
  );
  return merged;
}

export function deleteList(id: string) {
  db.prepare(`DELETE FROM email_subscribers WHERE list_id = ?`).run(id);
  db.prepare(`DELETE FROM email_lists WHERE id = ?`).run(id);
}

export function addSubscriber(input: {
  list_id: string;
  email: string;
  first_name?: string;
  last_name?: string;
  phone?: string;
  company?: string;
  tags?: string;
  custom_fields?: string;
}): Subscriber {
  const id = uid("es_");
  const t = now();
  db.prepare(
    `INSERT INTO email_subscribers (id, list_id, email, first_name, last_name, phone, company, tags, custom_fields, status, created_at, updated_at)
     VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, 'pending', ?, ?)`,
  ).run(id, input.list_id, input.email, input.first_name || null, input.last_name || null, input.phone || null, input.company || null, input.tags || null, input.custom_fields || null, t, t);
  db.prepare(`UPDATE email_lists SET subscribers_count = subscribers_count + 1, updated_at = ? WHERE id = ?`).run(t, input.list_id);
  return getSubscriber(id)!;
}

export function getSubscriber(id: string): Subscriber | null {
  const row = db.prepare(`SELECT * FROM email_subscribers WHERE id = ?`).get(id) as Record<string, unknown> | undefined;
  return row ? (row as Subscriber) : null;
}

export function getSubscriberByEmail(email: string, listId?: string): Subscriber | null {
  if (listId) {
    const row = db.prepare(`SELECT * FROM email_subscribers WHERE email = ? AND list_id = ?`).get(email, listId) as Record<string, unknown> | undefined;
    return row ? (row as Subscriber) : null;
  }
  const row = db.prepare(`SELECT * FROM email_subscribers WHERE email = ? LIMIT 1`).get(email) as Record<string, unknown> | undefined;
  return row ? (row as Subscriber) : null;
}

export function listSubscribers(listId?: string, status?: string): Subscriber[] {
  let sql = `SELECT * FROM email_subscribers WHERE 1=1`;
  const args: (string | number)[] = [];
  if (listId) { sql += ` AND list_id = ?`; args.push(listId); }
  if (status) { sql += ` AND status = ?`; args.push(status); }
  sql += ` ORDER BY created_at DESC`;
  return db.prepare(sql).all(...args) as Record<string, unknown>[];
}

export function updateSubscriber(id: string, patch: Partial<Subscriber>): Subscriber | null {
  const cur = getSubscriber(id);
  if (!cur) return null;
  const merged = { ...cur, ...patch, updated_at: now() };
  const sets: string[] = [];
  const vals: (string | number | null)[] = [];
  if (patch.email !== undefined) { sets.push("email = ?"); vals.push(patch.email); }
  if (patch.first_name !== undefined) { sets.push("first_name = ?"); vals.push(patch.first_name || null); }
  if (patch.last_name !== undefined) { sets.push("last_name = ?"); vals.push(patch.last_name || null); }
  if (patch.status !== undefined) { sets.push("status = ?"); vals.push(patch.status); }
  if (patch.tags !== undefined) { sets.push("tags = ?"); vals.push(patch.tags || null); }
  if (patch.custom_fields !== undefined) { sets.push("custom_fields = ?"); vals.push(patch.custom_fields || null); }
  if (sets.length === 0) return cur;
  sets.push("updated_at = ?");
  vals.push(now());
  vals.push(id);
  db.prepare(`UPDATE email_subscribers SET ${sets.join(", ")} WHERE id = ?`).run(...vals);
  return getSubscriber(id);
}

export function unsubscribe(email: string, listId?: string): boolean {
  const sub = getSubscriberByEmail(email, listId);
  if (!sub) return false;
  db.prepare(`UPDATE email_subscribers SET status = 'unsubscribed', unsubscribed_at = ?, updated_at = ? WHERE id = ?`).run(now(), now(), sub.id);
  return true;
}

export function deleteSubscriber(id: string) {
  const sub = getSubscriber(id);
  if (sub) {
    db.prepare(`UPDATE email_lists SET subscribers_count = subscribers_count - 1, updated_at = ? WHERE id = ?`).run(now(), sub.list_id);
  }
  db.prepare(`DELETE FROM email_subscribers WHERE id = ?`).run(id);
}

export function importSubscribers(listId: string, emails: Array<{ email: string; first_name?: string; last_name?: string; phone?: string; company?: string }>): { imported: number; skipped: number; errors: string[] } {
  let imported = 0;
  let skipped = 0;
  const errors: string[] = [];
  for (const e of emails) {
    try {
      const existing = getSubscriberByEmail(e.email, listId);
      if (existing) {
        skipped++;
        continue;
      }
      addSubscriber({ list_id: listId, ...e });
      imported++;
    } catch (err) {
      errors.push(`${e.email}: ${err instanceof Error ? err.message : "unknown error"}`);
    }
  }
  return { imported, skipped, errors };
}

