export interface EmailTemplate {
  id: string;
  name: string;
  description: string;
  subject: string;
  preheader: string;
  body_html: string;
  body_text?: string;
  thumbnail_url?: string;
  category: "welcome" | "newsletter" | "promo" | "transactional" | "follow_up" | "re_engagement" | "custom";
}

export interface PersonalizationContext {
  email: string;
  first_name?: string;
  last_name?: string;
  name?: string;
  company?: string;
  phone?: string;
  custom_fields?: Record<string, string>;
  unsubscribe_url?: string;
  view_in_browser_url?: string;
}

export function personalizeTemplate(template: string, ctx: PersonalizationContext): string {
  let html = template;

  const fullName = [ctx.first_name, ctx.last_name].filter(Boolean).join(" ") || ctx.name || "there";
  const firstName = ctx.first_name || "";

  const vars: Record<string, string> = {
    "{{name}}": fullName,
    "{{first_name}}": firstName,
    "{{last_name}}": ctx.last_name || "",
    "{{email}}": ctx.email,
    "{{company}}": ctx.company || "",
    "{{phone}}": ctx.phone || "",
    "{{unsubscribe_url}}": ctx.unsubscribe_url || "#",
    "{{view_in_browser_url}}": ctx.view_in_browser_url || "#",
  };

  if (ctx.custom_fields) {
    for (const [key, value] of Object.entries(ctx.custom_fields)) {
      vars[`{{${key}}}`] = value;
    }
  }

  for (const [token, value] of Object.entries(vars)) {
    html = html.split(token).join(value);
  }

  html = addTrackingPixel(html);
  html = linkifyTrackingLinks(html);

  return html;
}

export function personalizeSubject(subject: string, ctx: PersonalizationContext): string {
  let s = subject;
  const fullName = [ctx.first_name, ctx.last_name].filter(Boolean).join(" ") || ctx.name || "there";
  s = s.split("{{name}}").join(fullName);
  s = s.split("{{first_name}}").join(ctx.first_name || "");
  s = s.split("{{email}}").join(ctx.email);
  return s;
}

export function addTrackingPixel(html: string): string {
  const pixel = '<img src="https://example.com/track/open/{{outbox_id}}" width="1" height="1" style="display:block" alt="" />';
  if (html.includes("</body>")) {
    return html.replace("</body>", `${pixel}</body>`);
  }
  return html + pixel;
}

export function linkifyTrackingLinks(html: string): string {
  return html;
}

export function renderTemplate(template: EmailTemplate, ctx: PersonalizationContext): { subject: string; html: string; text: string } {
  const subject = personalizeSubject(template.subject, ctx);
  const html = personalizeTemplate(template.body_html, ctx);
  const text = template.body_text ? personalizeTemplate(template.body_text, ctx) : stripHtml(html);
  return { subject, html, text };
}

function stripHtml(html: string): string {
  return html.replace(/<[^>]+>/g, "").replace(/\s+/g, " ").trim();
}

