import { db, uid, now } from "@/lib/db";
import { getSubscriber } from "./lists";
import { queueAndSend } from "@/lib/email";

export interface SequenceStep {
  id: string;
  sequence_id: string;
  sort_order: number;
  name: string;
  subject: string;
  body_html: string;
  body_text?: string;
  delay_days: number;
  delay_hours: number;
}

export interface SequenceEnrollment {
  id: string;
  sequence_id: string;
  subscriber_id: string;
  current_step: number;
  status: "active" | "paused" | "completed" | "cancelled";
  enrolled_at: number;
  next_step_at?: number;
  completed_at?: number;
}

export interface EmailSequence {
  id: string;
  workspace_id: string;
  name: string;
  description?: string;
  trigger_event?: string;
  trigger_delay_hours: number;
  active: boolean;
  enrolled_count: number;
  completed_count: number;
  created_at: number;
  updated_at: number;
}

export function createSequence(input: { name: string; description?: string; trigger_event?: string; trigger_delay_hours?: number; workspace_id?: string }): EmailSequence {
  const id = uid("esq_");
  const t = now();
  db.prepare(
    `INSERT INTO email_sequences (id, workspace_id, name, description, trigger_event, trigger_delay_hours, active, enrolled_count, completed_count, created_at, updated_at)
     VALUES (?, ?, ?, ?, ?, ?, 1, 0, 0, ?, ?)`,
  ).run(id, input.workspace_id || "default", input.name, input.description || null, input.trigger_event || null, input.trigger_delay_hours || 0, t, t);
  return getSequence(id)!;
}

export function getSequence(id: string): EmailSequence | null {
  const row = db.prepare(`SELECT * FROM email_sequences WHERE id = ?`).get(id) as Record<string, unknown> | undefined;
  return row ? (row as EmailSequence) : null;
}

export function listSequences(workspaceId = "default"): EmailSequence[] {
  return db.prepare(`SELECT * FROM email_sequences WHERE workspace_id = ? ORDER BY created_at DESC`).all(workspaceId) as Record<string, unknown>[];
}

export function updateSequence(id: string, patch: Partial<EmailSequence>): EmailSequence | null {
  const cur = getSequence(id);
  if (!cur) return null;
  const merged = { ...cur, ...patch, updated_at: now() };
  db.prepare(`UPDATE email_sequences SET name=?, description=?, trigger_event=?, active=?, updated_at=? WHERE id=?`).run(
    merged.name, merged.description || null, merged.trigger_event || null, merged.active ? 1 : 0, merged.updated_at, id,
  );
  return merged;
}

export function deleteSequence(id: string) {
  db.prepare(`DELETE FROM email_sequence_steps WHERE sequence_id = ?`).run(id);
  db.prepare(`DELETE FROM email_sequence_enrollments WHERE sequence_id = ?`).run(id);
  db.prepare(`DELETE FROM email_sequences WHERE id = ?`).run(id);
}

export function addSequenceStep(input: {
  sequence_id: string;
  name: string;
  subject: string;
  body_html: string;
  body_text?: string;
  delay_days?: number;
  delay_hours?: number;
  sort_order?: number;
}): SequenceStep {
  const id = uid("ess_");
  const t = now();
  db.prepare(
    `INSERT INTO email_sequence_steps (id, sequence_id, sort_order, name, subject, body_html, body_text, delay_days, delay_hours, created_at, updated_at)
     VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
  ).run(id, input.sequence_id, input.sort_order || 0, input.name, input.subject, input.body_html, input.body_text || null, input.delay_days || 0, input.delay_hours || 0, t, t);
  return getSequenceStep(id)!;
}

export function getSequenceStep(id: string): SequenceStep | null {
  const row = db.prepare(`SELECT * FROM email_sequence_steps WHERE id = ?`).get(id) as Record<string, unknown> | undefined;
  return row ? (row as SequenceStep) : null;
}

export function listSequenceSteps(sequenceId: string): SequenceStep[] {
  return db.prepare(`SELECT * FROM email_sequence_steps WHERE sequence_id = ? ORDER BY sort_order ASC, delay_days ASC, delay_hours ASC`).all(sequenceId) as Record<string, unknown>[];
}

export function updateSequenceStep(id: string, patch: Partial<SequenceStep>): SequenceStep | null {
  const cur = getSequenceStep(id);
  if (!cur) return null;
  const merged = { ...cur, ...patch, updated_at: now() };
  db.prepare(`UPDATE email_sequence_steps SET name=?, subject=?, body_html=?, body_text=?, delay_days=?, delay_hours=?, sort_order=?, updated_at=? WHERE id=?`).run(
    merged.name, merged.subject, merged.body_html, merged.body_text || null, merged.delay_days, merged.delay_hours, merged.sort_order, merged.updated_at, id,
  );
  return merged;
}

export function deleteSequenceStep(id: string) {
  db.prepare(`DELETE FROM email_sequence_steps WHERE id = ?`).run(id);
}

export function enrollSubscriber(sequenceId: string, subscriberId: string): SequenceEnrollment {
  const id = uid("ese_");
  const t = now();
  const steps = listSequenceSteps(sequenceId);
  const nextStepAt = steps.length > 0 ? t + (steps[0].delay_days * 86400000) + (steps[0].delay_hours * 3600000) : null;

  db.prepare(
    `INSERT INTO email_sequence_enrollments (id, sequence_id, subscriber_id, current_step, status, enrolled_at, next_step_at, created_at, updated_at)
     VALUES (?, ?, ?, 0, 'active', ?, ?, ?, ?)`,
  ).run(id, sequenceId, subscriberId, t, nextStepAt, t, t);

  db.prepare(`UPDATE email_sequences SET enrolled_count = enrolled_count + 1, updated_at = ? WHERE id = ?`).run(t, sequenceId);

  const enrollment = getEnrollment(id)!;
  if (nextStepAt && steps.length > 0) {
    scheduleStep(enrollment, steps[0]);
  }

  return enrollment;
}

export function getEnrollment(id: string): SequenceEnrollment | null {
  const row = db.prepare(`SELECT * FROM email_sequence_enrollments WHERE id = ?`).get(id) as Record<string, unknown> | undefined;
  return row ? (row as SequenceEnrollment) : null;
}

export function listEnrollments(sequenceId?: string): SequenceEnrollment[] {
  if (sequenceId) {
    return db.prepare(`SELECT * FROM email_sequence_enrollments WHERE sequence_id = ? ORDER BY enrolled_at DESC`).all(sequenceId) as Record<string, unknown>[];
  }
  return db.prepare(`SELECT * FROM email_sequence_enrollments ORDER BY enrolled_at DESC LIMIT 500`).all() as Record<string, unknown>[];
}

export function cancelEnrollment(id: string, reason = "manual") {
  db.prepare(`UPDATE email_sequence_enrollments SET status = 'cancelled', updated_at = ? WHERE id = ?`).run(now(), id);
}

export function tickSequences(nowMs = Date.now()): number {
  const due = db
    .prepare(
      `SELECT e.*, s.steps AS seq_steps FROM email_sequence_enrollments e
       JOIN email_sequences s ON s.id = e.sequence_id
       WHERE e.status = 'active' AND e.next_step_at <= ? AND s.active = 1
       LIMIT 100`,
    )
    .all(nowMs) as Record<string, unknown>[];

  let fired = 0;
  for (const e of due) {
    let steps: SequenceStep[] = [];
    try { steps = JSON.parse(e.seq_steps as string); } catch { continue; }

    const nextStepIdx = (e.current_step as number) + 1;
    if (nextStepIdx >= steps.length) {
      db.prepare(`UPDATE email_sequence_enrollments SET status = 'completed', completed_at = ?, updated_at = ? WHERE id = ?`).run(nowMs, nowMs, e.id);
      db.prepare(`UPDATE email_sequences SET completed_count = completed_count + 1, updated_at = ? WHERE id = ?`).run(nowMs, e.sequence_id);
      continue;
    }

    const step = steps[nextStepIdx];
    const nextActionAt = nowMs + (step.delay_days * 86400000) + (step.delay_hours * 3600000);

    db.prepare(
      `UPDATE email_sequence_enrollments SET current_step = ?, next_step_at = ?, updated_at = ? WHERE id = ?`,
    ).run(nextStepIdx, nextActionAt, nowMs, e.id);

    const subscriber = getSubscriber(e.subscriber_id as string);
    if (subscriber && step.body_html) {
      queueAndSend({
        to: subscriber.email,
        toName: [subscriber.first_name, subscriber.last_name].filter(Boolean).join(" ") || undefined,
        subject: step.subject,
        html: step.body_html,
        text: step.body_text || undefined,
        automation_id: e.sequence_id as string,
        contact_id: e.subscriber_id as string,
      }).catch(() => {});
    }
    fired++;
  }
  return fired;
}

function scheduleStep(enrollment: SequenceEnrollment, step: SequenceStep) {
  const delayMs = (step.delay_days * 86400000) + (step.delay_hours * 3600000);
  const nextStepAt = enrollment.enrolled_at + delayMs;
  db.prepare(`UPDATE email_sequence_enrollments SET next_step_at = ?, updated_at = ? WHERE id = ?`).run(nextStepAt, now(), enrollment.id);
}

