+
+export function getABVariant(id: string): ABVariant | null {
+  const row = db.prepare(`SELECT * FROM email_ab_variants WHERE id = ?`).get(id) as Record<string, unknown> | undefined;
+  return row ? (row as ABVariant) : null;
+}
+
+export function listABVariants(abTestId: string): ABVariant[] {
+  return db.prepare(`SELECT * FROM email_ab_variants WHERE ab_test_id = ? ORDER BY created_at ASC`).all(abTestId) as Record<string, unknown>[];
+}
+
+export function recordABEvent(variantId: string, eventType: "open" | "click" | "bounce" | "unsubscribe") {
+  const field = eventType === "open" ? "opens" : eventType === "click" ? "clicks" : eventType === "bounce" ? "bounces" : "unsubscribes";
+  db.prepare(`UPDATE email_ab_variants SET ${field} = ${field} + 1, updated_at = ? WHERE id = ?`).run(now(), variantId);
+}
+
+export function startABTest(id: string): ABTest | null {
+  const test = getABTest(id);
+  if (!test || test.status !== "draft") return null;
+  const variants = listABVariants(id);
+  if (variants.length < 2) return null;
+
+  const updated = updateABTest(id, { status: "running", started_at: now() });
+  return updated;
+}
+
+export function calculateABWinner(abTestId: string): { winner?: ABVariant; confidence: number; recommendation: string } {
+  const variants = listABVariants(abTestId);
+  if (variants.length < 2) return { confidence: 0, recommendation: "Need at least 2 variants" };
+
+  const test = getABTest(abTestId);
+  const criteria = test?.winner_criteria || "open_rate";
+
+  let best: ABVariant | undefined;
+  let bestRate = -1;
+
+  for (const v of variants) {
+    let rate = 0;
+    if (criteria === "open_rate" && v.sends > 0) rate = v.opens / v.sends;
+    else if (criteria === "click_rate" && v.sends > 0) rate = v.clicks / v.sends;
+    else if (criteria === "conversion_rate" && v.sends > 0) rate = v.clicks / v.sends;
+
+    if (rate > bestRate) {
+      bestRate = rate;
+      best = v;
+    }
+  }
+
+  if (!best) return { confidence: 0, recommendation: "No data yet" };
+
+  const confidence = calculateConfidence(variants, criteria);
+  return {
+    winner: best,
+    confidence,
+    recommendation: confidence >= 0.95 ? `${best.name} is the winner with ${(confidence * 100).toFixed(0)}% confidence` : "Keep testing — not enough data for statistical significance",
+  };
+}
+
+function calculateConfidence(variants: ABVariant[], criteria: string): number {
+  if (variants.length < 2) return 0;
+  const totalSends = variants.reduce((sum, v) => sum + v.sends, 0);
+  if (totalSends < 100) return 0.5;
+
+  const rates = variants.map(v => {
+    if (criteria === "open_rate") return v.sends > 0 ? v.opens / v.sends : 0;
+    if (criteria === "click_rate") return v.sends > 0 ? v.clicks / v.sends : 0;
+    return 0;
+  });
+
+  const maxRate = Math.max(...rates);
+  const minRate = Math.min(...rates);
+  const lift = maxRate - minRate;
+
+  if (lift < 0.01) return 0.6;
+  if (totalSends > 1000 && lift > 0.05) return 0.95;
+  if (totalSends > 500 && lift > 0.03) return 0.85;
+  return 0.7;
+}
+
+export function sendABTest(testId: string, subscriberEmail: string, subscriberName?: string): { variant: ABVariant; sent: boolean } | null {
+  const test = getABTest(testId);
+  if (!test || test.status !== "running") return null;
+
+  const variants = listABVariants(testId);
+  if (variants.length === 0) return null;
+
+  const variant = variants[Math.floor(Math.random() * variants.length)];
+  if (!variant) return null;
+
+  try {
+    queueAndSend({
+      to: subscriberEmail,
+      toName: subscriberName,
+      subject: variant.subject,
+      html: variant.body_html,
+    });
+    db.prepare(`UPDATE email_ab_variants SET sends = sends + 1, updated_at = ? WHERE id = ?`).run(now(), variant.id);
+    return { variant, sent: true };
+  } catch {
+    return { variant, sent: false };
+  }
+}

