import { db, now } from "@/lib/db";

export interface EmailAnalytics {
  id: string;
  workspace_id: string;
  email_id?: string;
  campaign_id?: string;
  list_id?: string;
  date: string;
  sends: number;
  opens: number;
  clicks: number;
  bounces: number;
  unsubscribes: number;
  spam_reports: number;
  unique_opens: number;
  unique_clicks: number;
  created_at: number;
}

export function recordEmailEvent(emailId: string, eventType: "send" | "open" | "click" | "bounce" | "unsubscribe" | "spam", listId?: string, campaignId?: string) {
  const today = new Date().toISOString().split("T")[0];
  const workspaceId = "default";

  let row = db.prepare(
    `SELECT * FROM email_analytics WHERE workspace_id = ? AND email_id = ? AND date = ?`
  ).get(workspaceId, emailId, today) as Record<string, unknown> | undefined;

  if (!row) {
    const id = `ea_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`;
    db.prepare(
      `INSERT INTO email_analytics (id, workspace_id, email_id, campaign_id, list_id, date, sends, opens, clicks, bounces, unsubscribes, spam_reports, unique_opens, unique_clicks, created_at)
       VALUES (?, ?, ?, ?, ?, ?, 0, 0, 0, 0, 0, 0, 0, 0, ?)`,
    ).run(id, workspaceId, emailId, campaignId || null, listId || null, today, now());
    row = db.prepare(`SELECT * FROM email_analytics WHERE id = ?`).get(id) as Record<string, unknown>;
  }

  const field = eventType === "send" ? "sends" : eventType === "open" ? "opens" : eventType === "click" ? "clicks" : eventType === "bounce" ? "bounces" : eventType === "unsubscribe" ? "unsubscribes" : "spam_reports";
  const uniqueField = eventType === "open" ? "unique_opens" : eventType === "click" ? "unique_clicks" : null;

  db.prepare(`UPDATE email_analytics SET ${field} = ${field} + 1${uniqueField ? `, ${uniqueField} = ${uniqueField} + 1` : ""}, updated_at = ? WHERE id = ?`).run(now(), row.id);
}

export function getEmailAnalytics(emailId?: string, days = 30): EmailAnalytics[] {
  const workspaceId = "default";
  const cutoff = new Date(Date.now() - days * 86400000).toISOString().split("T")[0];

  if (emailId) {
    return db.prepare(
      `SELECT * FROM email_analytics WHERE workspace_id = ? AND email_id = ? AND date >= ? ORDER BY date DESC`
    ).all(workspaceId, emailId, cutoff) as Record<string, unknown>[];
  }

  return db.prepare(
    `SELECT * FROM email_analytics WHERE workspace_id = ? AND date >= ? ORDER BY date DESC`
  ).all(workspaceId, cutoff) as Record<string, unknown>[];
}

export function getAggregatedAnalytics(workspaceId = "default", days = 30): {
  total_sends: number;
  total_opens: number;
  total_clicks: number;
  total_bounces: number;
  total_unsubscribes: number;
  total_spam: number;
  open_rate: number;
  click_rate: number;
  bounce_rate: number;
  unsubscribe_rate: number;
} {
  const cutoff = new Date(Date.now() - days * 86400000).toISOString().split("T")[0];

  const rows = db.prepare(
    `SELECT SUM(sends) as total_sends, SUM(opens) as total_opens, SUM(clicks) as total_clicks,
            SUM(bounces) as total_bounces, SUM(unsubscribes) as total_unsubscribes, SUM(spam_reports) as total_spam
     FROM email_analytics WHERE workspace_id = ? AND date >= ?`
  ).get(workspaceId, cutoff) as Record<string, unknown>;

  const sends = Number(rows.total_sends) || 0;
  const opens = Number(rows.total_opens) || 0;
  const clicks = Number(rows.total_clicks) || 0;
  const bounces = Number(rows.total_bounces) || 0;
  const unsubscribes = Number(rows.total_unsubscribes) || 0;

  return {
    total_sends: sends,
    total_opens: opens,
    total_clicks: clicks,
    total_bounces: bounces,
    total_unsubscribes: unsubscribes,
    total_spam: Number(rows.total_spam) || 0,
    open_rate: sends > 0 ? Number((opens / sends * 100).toFixed(2)) : 0,
    click_rate: sends > 0 ? Number((clicks / sends * 100).toFixed(2)) : 0,
    bounce_rate: sends > 0 ? Number((bounces / sends * 100).toFixed(2)) : 0,
    unsubscribe_rate: sends > 0 ? Number((unsubscribes / sends * 100).toFixed(2)) : 0,
  };
}

export function getTopPerformingEmails(workspaceId = "default", days = 30, limit = 10): Array<{ email_id: string; sends: number; opens: number; clicks: number; open_rate: number; click_rate: number }> {
  const cutoff = new Date(Date.now() - days * 86400000).toISOString().split("T")[0];

  const rows = db.prepare(
    `SELECT email_id, SUM(sends) as sends, SUM(opens) as opens, SUM(clicks) as clicks
     FROM email_analytics WHERE workspace_id = ? AND date >= ? AND email_id IS NOT NULL
     GROUP BY email_id ORDER BY opens DESC LIMIT ?`
  ).all(workspaceId, cutoff, limit) as Record<string, unknown>[];

  return rows.map(r => ({
    email_id: r.email_id as string,
    sends: Number(r.sends) || 0,
    opens: Number(r.opens) || 0,
    clicks: Number(r.clicks) || 0,
    open_rate: Number(r.sends) > 0 ? Number(((Number(r.opens) / Number(r.sends)) * 100).toFixed(2)) : 0,
    click_rate: Number(r.sends) > 0 ? Number(((Number(r.clicks) / Number(r.sends)) * 100).toFixed(2)) : 0,
  }));
}

export function getSubscriberEngagement(listId?: string): { total: number; subscribed: number; unsubscribed: number; bounced: number; pending: number } {
  let sql = `SELECT status, COUNT(*) as count FROM email_subscribers WHERE 1=1`;
  const args: (string | number)[] = [];
  if (listId) { sql += ` AND list_id = ?`; args.push(listId); }
  sql += ` GROUP BY status`;

  const rows = db.prepare(sql).all(...args) as Record<string, unknown>[];
  const result = { total: 0, subscribed: 0, unsubscribed: 0, bounced: 0, pending: 0 };

  for (const r of rows) {
    const count = Number(r.count) || 0;
    result.total += count;
    if (r.status === "subscribed") result.subscribed = count;
    else if (r.status === "unsubscribed") result.unsubscribed = count;
    else if (r.status === "bounced") result.bounced = count;
    else if (r.status === "pending") result.pending = count;
  }

  return result;
}

