+  if (listId) { sql += ` AND list_id = ?`; args.push(listId); }
+  sql += ` GROUP BY status`;
+
+  const rows = db.prepare(sql).all(...args) as Record<string, unknown>[];
+  const result = { total: 0, subscribed: 0, unsubscribed: 0, bounced: 0, pending: 0 };
+
+  for (const r of rows) {
+    const count = Number(r.count) || 0;
+    result.total += count;
+    if (r.status === "subscribed") result.subscribed = count;
+    else if (r.status === "unsubscribed") result.unsubscribed = count;
+    else if (r.status === "bounced") result.bounced = count;
+    else if (r.status === "pending") result.pending = count;
+  }
+
+  return result;
+}

