import { NextResponse } from "next/server";
import { listSubscribers, addSubscriber, updateSubscriber, deleteSubscriber, unsubscribe as doUnsubscribe, importSubscribers } from "@/lib/email-marketing/lists";

export async function GET(request: Request) {
  try {
    const { searchParams } = new URL(request.url);
    const listId = searchParams.get("list_id") || undefined;
    const status = searchParams.get("status") || undefined;
    const subscribers = listSubscribers(listId, status);
    return NextResponse.json(subscribers);
  } catch (error) {
    console.error("Error fetching subscribers:", error);
    return NextResponse.json({ error: "Failed to fetch subscribers" }, { status: 500 });
  }
}

export async function POST(request: Request) {
  try {
    const body = await request.json();
    const { list_id, email, first_name, last_name, phone, company, tags, custom_fields } = body;
    if (!list_id || !email) return NextResponse.json({ error: "list_id and email are required" }, { status: 400 });

    const existing = listSubscribers(list_id).find(s => s.email === email);
    if (existing) return NextResponse.json({ error: "Subscriber already exists" }, { status: 409 });

    const subscriber = addSubscriber({ list_id, email, first_name, last_name, phone, company, tags, custom_fields });
    return NextResponse.json(subscriber, { status: 201 });
  } catch (error) {
    console.error("Error adding subscriber:", error);
    return NextResponse.json({ error: "Failed to add subscriber" }, { status: 500 });
  }
}

export async function PATCH(request: Request) {
  try {
    const body = await request.json();
    const { id, email, first_name, last_name, status, tags, custom_fields } = body;
    if (!id) return NextResponse.json({ error: "id is required" }, { status: 400 });
    const subscriber = updateSubscriber(id, { email, first_name, last_name, status, tags, custom_fields });
    if (!subscriber) return NextResponse.json({ error: "Subscriber not found" }, { status: 404 });
    return NextResponse.json(subscriber);
  } catch (error) {
    console.error("Error updating subscriber:", error);
    return NextResponse.json({ error: "Failed to update subscriber" }, { status: 500 });
  }
}

export async function DELETE(request: Request) {
  try {
    const body = await request.json();
    const { id } = body;
    if (!id) return NextResponse.json({ error: "id is required" }, { status: 400 });
    deleteSubscriber(id);
    return NextResponse.json({ success: true });
  } catch (error) {
    console.error("Error deleting subscriber:", error);
    return NextResponse.json({ error: "Failed to delete subscriber" }, { status: 500 });
  }
}

export async function POST_IMPORT(request: Request) {
  try {
    const body = await request.json();
    const { list_id, subscribers } = body;
    if (!list_id || !Array.isArray(subscribers)) return NextResponse.json({ error: "list_id and subscribers array are required" }, { status: 400 });
    const result = importSubscribers(list_id, subscribers);
    return NextResponse.json(result, { status: 201 });
  } catch (error) {
    console.error("Error importing subscribers:", error);
    return NextResponse.json({ error: "Failed to import subscribers" }, { status: 500 });
  }
}

