import { NextResponse } from "next/server";
import { addSequenceStep, listSequenceSteps, updateSequenceStep, deleteSequenceStep } from "@/lib/email-marketing/sequences";

export async function GET(request: Request) {
  try {
    const { searchParams } = new URL(request.url);
    const sequenceId = searchParams.get("sequence_id");
    if (!sequenceId) return NextResponse.json({ error: "sequence_id is required" }, { status: 400 });
    const steps = listSequenceSteps(sequenceId);
    return NextResponse.json(steps);
  } catch (error) {
    console.error("Error fetching steps:", error);
    return NextResponse.json({ error: "Failed to fetch steps" }, { status: 500 });
  }
}

export async function POST(request: Request) {
  try {
    const body = await request.json();
    const { sequence_id, name, subject, body_html, body_text, delay_days, delay_hours, sort_order } = body;
    if (!sequence_id || !name || !subject || !body_html) {
      return NextResponse.json({ error: "sequence_id, name, subject, and body_html are required" }, { status: 400 });
    }
    const step = addSequenceStep({ sequence_id, name, subject, body_html, body_text, delay_days, delay_hours, sort_order });
    return NextResponse.json(step, { status: 201 });
  } catch (error) {
    console.error("Error creating step:", error);
    return NextResponse.json({ error: "Failed to create step" }, { status: 500 });
  }
}

export async function PATCH(request: Request) {
  try {
    const body = await request.json();
    const { id, name, subject, body_html, body_text, delay_days, delay_hours, sort_order } = body;
    if (!id) return NextResponse.json({ error: "id is required" }, { status: 400 });
    const step = updateSequenceStep(id, { name, subject, body_html, body_text, delay_days, delay_hours, sort_order });
    if (!step) return NextResponse.json({ error: "Step not found" }, { status: 404 });
    return NextResponse.json(step);
  } catch (error) {
    console.error("Error updating step:", error);
    return NextResponse.json({ error: "Failed to update step" }, { status: 500 });
  }
}

export async function DELETE(request: Request) {
  try {
    const body = await request.json();
    const { id } = body;
    if (!id) return NextResponse.json({ error: "id is required" }, { status: 400 });
    deleteSequenceStep(id);
    return NextResponse.json({ success: true });
  } catch (error) {
    console.error("Error deleting step:", error);
    return NextResponse.json({ error: "Failed to delete step" }, { status: 500 });
  }
}

