import { NextResponse } from "next/server";
import { enrollSubscriber, listEnrollments, cancelEnrollment, tickSequences } from "@/lib/email-marketing/sequences";

export async function POST(request: Request) {
  try {
    const body = await request.json();
    const { sequence_id, subscriber_id } = body;
    if (!sequence_id || !subscriber_id) {
      return NextResponse.json({ error: "sequence_id and subscriber_id are required" }, { status: 400 });
    }
    const enrollment = enrollSubscriber(sequence_id, subscriber_id);
    return NextResponse.json(enrollment, { status: 201 });
  } catch (error) {
    console.error("Error enrolling subscriber:", error);
    return NextResponse.json({ error: "Failed to enroll subscriber" }, { status: 500 });
  }
}

export async function GET(request: Request) {
  try {
    const { searchParams } = new URL(request.url);
    const sequence_id = searchParams.get("sequence_id") || undefined;
    const enrollments = listEnrollments(sequence_id);
    return NextResponse.json(enrollments);
  } catch (error) {
    console.error("Error fetching enrollments:", error);
    return NextResponse.json({ error: "Failed to fetch enrollments" }, { status: 500 });
  }
}

export async function POST_TICK() {
  try {
    const fired = tickSequences();
    return NextResponse.json({ fired });
  } catch (error) {
    console.error("Error ticking sequences:", error);
    return NextResponse.json({ error: "Failed to tick sequences" }, { status: 500 });
  }
}

