import { NextResponse } from "next/server";
import { createABTest, listABTests, getABTest, updateABTest, deleteABTest, addABVariant, listABVariants, startABTest, calculateABWinner, sendABTest } from "@/lib/email-marketing/ab-testing";

export async function GET(request: Request) {
  try {
    const tests = listABTests();
    return NextResponse.json(tests);
  } catch (error) {
    console.error("Error fetching AB tests:", error);
    return NextResponse.json({ error: "Failed to fetch AB tests" }, { status: 500 });
  }
}

export async function POST(request: Request) {
  try {
    const body = await request.json();
    const { name, email_id, traffic_split, winner_criteria, sample_size } = body;
    if (!name) return NextResponse.json({ error: "name is required" }, { status: 400 });
    const test = createABTest({ name, email_id, traffic_split, winner_criteria, sample_size });
    return NextResponse.json(test, { status: 201 });
  } catch (error) {
    console.error("Error creating AB test:", error);
    return NextResponse.json({ error: "Failed to create AB test" }, { status: 500 });
  }
}

export async function PATCH(request: Request) {
  try {
    const body = await request.json();
    const { id, name, status, winner_criteria } = body;
    if (!id) return NextResponse.json({ error: "id is required" }, { status: 400 });
    const test = updateABTest(id, { name, status, winner_criteria });
    if (!test) return NextResponse.json({ error: "AB test not found" }, { status: 404 });
    return NextResponse.json(test);
  } catch (error) {
    console.error("Error updating AB test:", error);
    return NextResponse.json({ error: "Failed to update AB test" }, { status: 500 });
  }
}

export async function DELETE(request: Request) {
  try {
    const body = await request.json();
    const { id } = body;
    if (!id) return NextResponse.json({ error: "id is required" }, { status: 400 });
    deleteABTest(id);
    return NextResponse.json({ success: true });
  } catch (error) {
    console.error("Error deleting AB test:", error);
    return NextResponse.json({ error: "Failed to delete AB test" }, { status: 500 });
  }
}

