import { NextResponse } from "next/server";
import { addABVariant, listABVariants, startABTest, calculateABWinner, sendABTest } from "@/lib/email-marketing/ab-testing";

export async function GET(request: Request) {
  try {
    const { searchParams } = new URL(request.url);
    const ab_test_id = searchParams.get("ab_test_id");
    if (!ab_test_id) return NextResponse.json({ error: "ab_test_id is required" }, { status: 400 });
    const variants = listABVariants(ab_test_id);
    return NextResponse.json(variants);
  } catch (error) {
    console.error("Error fetching variants:", error);
    return NextResponse.json({ error: "Failed to fetch variants" }, { status: 500 });
  }
}

export async function POST(request: Request) {
  try {
    const body = await request.json();
    const { ab_test_id, name, subject, body_html, is_control } = body;
    if (!ab_test_id || !name || !subject || !body_html) {
      return NextResponse.json({ error: "ab_test_id, name, subject, and body_html are required" }, { status: 400 });
    }
    const variant = addABVariant({ ab_test_id, name, subject, body_html, is_control });
    return NextResponse.json(variant, { status: 201 });
  } catch (error) {
    console.error("Error creating variant:", error);
    return NextResponse.json({ error: "Failed to create variant" }, { status: 500 });
  }
}

export async function POST_START(request: Request) {
  try {
    const body = await request.json();
    const { id } = body;
    if (!id) return NextResponse.json({ error: "id is required" }, { status: 400 });
    const test = startABTest(id);
    if (!test) return NextResponse.json({ error: "Cannot start test" }, { status: 400 });
    return NextResponse.json(test);
  } catch (error) {
    console.error("Error starting AB test:", error);
    return NextResponse.json({ error: "Failed to start AB test" }, { status: 500 });
  }
}

export async function POST_WINNER(request: Request) {
  try {
    const body = await request.json();
    const { id } = body;
    if (!id) return NextResponse.json({ error: "id is required" }, { status: 400 });
    const result = calculateABWinner(id);
    return NextResponse.json(result);
  } catch (error) {
    console.error("Error calculating winner:", error);
    return NextResponse.json({ error: "Failed to calculate winner" }, { status: 500 });
  }
}

