import { NextResponse } from "next/server";
import { getAggregatedAnalytics, getEmailAnalytics, getTopPerformingEmails, getSubscriberEngagement } from "@/lib/email-marketing/analytics";

export async function GET(request: Request) {
  try {
    const { searchParams } = new URL(request.url);
    const email_id = searchParams.get("email_id") || undefined;
    const days = Number(searchParams.get("days")) || 30;

    if (email_id) {
      const analytics = getEmailAnalytics(email_id, days);
      return NextResponse.json(analytics);
    }

    const aggregated = getAggregatedAnalytics("default", days);
    const topEmails = getTopPerformingEmails("default", days, 10);
    const engagement = getSubscriberEngagement();

    return NextResponse.json({
      aggregated,
      topEmails,
      engagement,
      days,
    });
  } catch (error) {
    console.error("Error fetching analytics:", error);
    return NextResponse.json({ error: "Failed to fetch analytics" }, { status: 500 });
  }
}

