"use client";

import { useState, useEffect } from "react";
import { Card } from "@/components/ui";
import { Button } from "@/components/ui";
import { Input } from "@/components/ui";
import { Badge } from "@/components/marketing/ui";

type EmailList = {
  id: string;
  name: string;
  description?: string;
  subscribers_count: number;
  created_at: number;
};

export function ListManager() {
  const [lists, setLists] = useState<EmailList[]>([]);
  const [showForm, setShowForm] = useState(false);
  const [name, setName] = useState("");
  const [description, setDescription] = useState("");

  useEffect(() => {
    fetchLists();
  }, []);

  const fetchLists = async () => {
    try {
      const res = await fetch("/api/email/lists");
      const data = await res.json();
      setLists(data || []);
    } catch (e) {
      console.error(e);
    }
  };

  const createList = async () => {
    if (!name) return;
    await fetch("/api/email/lists", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ name, description }),
    });
    setName("");
    setDescription("");
    setShowForm(false);
    fetchLists();
  };

  const deleteList = async (id: string) => {
    if (!confirm("Delete this list and all its subscribers?")) return;
    await fetch("/api/email/lists", {
      method: "DELETE",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ id }),
    });
    fetchLists();
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h2 className="text-xl font-bold">Email Lists</h2>
        <Button onClick={() => setShowForm(!showForm)}>{showForm ? "Cancel" : "New List"}</Button>
      </div>

      {showForm && (
        <Card className="p-6 space-y-4">
          <div>
            <label className="block text-sm font-medium mb-1">List Name</label>
            <Input value={name} onChange={e => setName(e.target.value)} placeholder="Newsletter subscribers" />
          </div>
          <div>
            <label className="block text-sm font-medium mb-1">Description</label>
            <Input value={description} onChange={e => setDescription(e.target.value)} placeholder="Main newsletter list" />
          </div>
          <Button onClick={createList} disabled={!name}>Create List</Button>
        </Card>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {lists.map(list => (
          <Card key={list.id} className="p-4 space-y-3">
            <div>
              <h3 className="font-semibold">{list.name}</h3>
              <p className="text-sm text-gray-500">{list.description || "No description"}</p>
            </div>
            <div className="flex items-center justify-between">
              <Badge variant="outline">{list.subscribers_count} subscribers</Badge>
              <Button size="sm" variant="destructive" onClick={() => deleteList(list.id)}>Delete</Button>
            </div>
          </Card>
        ))}
      </div>

      {lists.length === 0 && (
        <Card className="p-8 text-center text-gray-500">
          No lists yet. Create your first email list to get started.
        </Card>
      )}
    </div>
  );
}

