"use client";

import { useState, useEffect } from "react";
import { Card } from "@/components/ui";
import { Button } from "@/components/ui";
import { Input } from "@/components/ui";
import { Badge } from "@/components/marketing/ui";
import { Select, SelectItem } from "@/components/marketing/ui";

type Subscriber = {
  id: string;
  list_id: string;
  email: string;
  first_name?: string;
  last_name?: string;
  company?: string;
  status: string;
  created_at: number;
};

export function SubscriberManager({ listId }: { listId?: string }) {
  const [subscribers, setSubscribers] = useState<Subscriber[]>([]);
  const [lists, setLists] = useState<Array<{ id: string; name: string }>>([]);
  const [showForm, setShowForm] = useState(false);
  const [form, setForm] = useState({ list_id: listId || "", email: "", first_name: "", last_name: "", company: "" });

  useEffect(() => {
    fetchSubscribers();
    fetchLists();
  }, [listId]);

  const fetchSubscribers = async () => {
    try {
      const url = listId ? `/api/email/subscribers?list_id=${listId}` : "/api/email/subscribers";
      const res = await fetch(url);
      const data = await res.json();
      setSubscribers(data || []);
    } catch (e) {
      console.error(e);
    }
  };

  const fetchLists = async () => {
    try {
      const res = await fetch("/api/email/lists");
      const data = await res.json();
      setLists(data || []);
    } catch (e) {
      console.error(e);
    }
  };

  const addSubscriber = async () => {
    if (!form.list_id || !form.email) return;
    await fetch("/api/email/subscribers", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(form),
    });
    setForm({ list_id: form.list_id, email: "", first_name: "", last_name: "", company: "" });
    setShowForm(false);
    fetchSubscribers();
  };

  const removeSubscriber = async (id: string) => {
    if (!confirm("Remove this subscriber?")) return;
    await fetch("/api/email/subscribers", {
      method: "DELETE",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ id }),
    });
    fetchSubscribers();
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h2 className="text-xl font-bold">Subscribers</h2>
        <Button onClick={() => setShowForm(!showForm)}>{showForm ? "Cancel" : "Add Subscriber"}</Button>
      </div>

      {showForm && (
        <Card className="p-6 space-y-4">
          <div>
            <label className="block text-sm font-medium mb-1">List</label>
            <Select value={form.list_id} onValueChange={v => setForm({ ...form, list_id: v })}>
              {lists.map(l => <SelectItem key={l.id} value={l.id}>{l.name}</SelectItem>)}
            </Select>
          </div>
          <div>
            <label className="block text-sm font-medium mb-1">Email</label>
            <Input value={form.email} onChange={e => setForm({ ...form, email: e.target.value })} placeholder="john@example.com" />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium mb-1">First Name</label>
              <Input value={form.first_name} onChange={e => setForm({ ...form, first_name: e.target.value })} />
            </div>
            <div>
              <label className="block text-sm font-medium mb-1">Last Name</label>
              <Input value={form.last_name} onChange={e => setForm({ ...form, last_name: e.target.value })} />
            </div>
          </div>
          <Button onClick={addSubscriber} disabled={!form.email || !form.list_id}>Add Subscriber</Button>
        </Card>
      )}

      <Card className="overflow-hidden">
        <table className="w-full text-sm">
          <thead className="bg-gray-50">
            <tr>
              <th className="px-4 py-3 text-left font-medium">Email</th>
              <th className="px-4 py-3 text-left font-medium">Name</th>
              <th className="px-4 py-3 text-left font-medium">Status</th>
              <th className="px-4 py-3 text-right font-medium">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100">
            {subscribers.map(sub => (
              <tr key={sub.id} className="hover:bg-gray-50">
                <td className="px-4 py-3">{sub.email}</td>
                <td className="px-4 py-3">{[sub.first_name, sub.last_name].filter(Boolean).join(" ") || "—"}</td>
                <td className="px-4 py-3">
                  <Badge className={sub.status === "subscribed" ? "bg-green-100 text-green-800" : "bg-gray-100 text-gray-800"}>
                    {sub.status}
                  </Badge>
                </td>
                <td className="px-4 py-3 text-right">
                  <Button size="sm" variant="destructive" onClick={() => removeSubscriber(sub.id)}>Remove</Button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        {subscribers.length === 0 && (
          <div className="p-8 text-center text-gray-500">No subscribers yet.</div>
        )}
      </Card>
    </div>
  );
}

