"use client";

import { useState, useEffect } from "react";
import { Card } from "@/components/ui";
import { Button } from "@/components/ui";
import { Input } from "@/components/ui";
import { Textarea } from "@/components/marketing/ui";
import { Badge } from "@/components/marketing/ui";

type Sequence = {
  id: string;
  name: string;
  description?: string;
  active: boolean;
  enrolled_count: number;
  completed_count: number;
};

type SequenceStep = {
  id: string;
  name: string;
  subject: string;
  body_html: string;
  body_text?: string;
  delay_days: number;
  delay_hours: number;
  sort_order: number;
};

export function SequenceBuilder() {
  const [sequences, setSequences] = useState<Sequence[]>([]);
  const [selectedSequence, setSelectedSequence] = useState<Sequence | null>(null);
  const [steps, setSteps] = useState<SequenceStep[]>([]);
  const [showForm, setShowForm] = useState(false);
  const [showStepForm, setShowStepForm] = useState(false);
  const [seqForm, setSeqForm] = useState({ name: "", description: "", trigger_event: "", trigger_delay_hours: 0 });
  const [stepForm, setStepForm] = useState({ name: "", subject: "", body_html: "", body_text: "", delay_days: 0, delay_hours: 0, sort_order: 0 });

  useEffect(() => {
    fetchSequences();
  }, []);

  const fetchSequences = async () => {
    try {
      const res = await fetch("/api/email/sequences");
      const data = await res.json();
      setSequences(data || []);
    } catch (e) {
      console.error(e);
    }
  };

  const selectSequence = async (seq: Sequence) => {
    setSelectedSequence(seq);
    try {
      const res = await fetch(`/api/email/sequences/steps?sequence_id=${seq.id}`);
      const data = await res.json();
      setSteps(data || []);
    } catch (e) {
      console.error(e);
    }
  };

  const createSequence = async () => {
    if (!seqForm.name) return;
    await fetch("/api/email/sequences", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(seqForm),
    });
    setSeqForm({ name: "", description: "", trigger_event: "", trigger_delay_hours: 0 });
    setShowForm(false);
    fetchSequences();
  };

  const addStep = async () => {
    if (!selectedSequence || !stepForm.name || !stepForm.subject || !stepForm.body_html) return;
    await fetch("/api/email/sequences/steps", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ ...stepForm, sequence_id: selectedSequence.id }),
    });
    setStepForm({ name: "", subject: "", body_html: "", body_text: "", delay_days: 0, delay_hours: 0, sort_order: 0 });
    setShowStepForm(false);
    selectSequence(selectedSequence);
  };

  const removeStep = async (id: string) => {
    if (!confirm("Remove this step?")) return;
    await fetch("/api/email/sequences/steps", {
      method: "DELETE",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ id }),
    });
    if (selectedSequence) selectSequence(selectedSequence);
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h2 className="text-xl font-bold">Email Sequences</h2>
        <Button onClick={() => setShowForm(!showForm)}>{showForm ? "Cancel" : "New Sequence"}</Button>
      </div>

      {showForm && (
        <Card className="p-6 space-y-4">
          <div>
            <label className="block text-sm font-medium mb-1">Sequence Name</label>
            <Input value={seqForm.name} onChange={e => setSeqForm({ ...seqForm, name: e.target.value })} placeholder="Onboarding sequence" />
          </div>
          <div>
            <label className="block text-sm font-medium mb-1">Description</label>
            <Input value={seqForm.description} onChange={e => setSeqForm({ ...seqForm, description: e.target.value })} placeholder="5-email welcome series" />
          </div>
          <div>
            <label className="block text-sm font-medium mb-1">Trigger Event</label>
            <Input value={seqForm.trigger_event} onChange={e => setSeqForm({ ...seqForm, trigger_event: e.target.value })} placeholder="signup, purchase, etc." />
          </div>
          <Button onClick={createSequence} disabled={!seqForm.name}>Create Sequence</Button>
        </Card>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <Card className="p-4 lg:col-span-1">
          <h3 className="font-semibold mb-3">Sequences</h3>
          <div className="space-y-2">
            {sequences.map(seq => (
              <button
                key={seq.id}
                onClick={() => selectSequence(seq)}
                className={`w-full text-left p-3 rounded-lg border transition-colors ${
                  selectedSequence?.id === seq.id ? "border-indigo-500 bg-indigo-50" : "border-gray-200 hover:border-indigo-300"
                }`}
              >
                <div className="font-medium text-sm">{seq.name}</div>
                <div className="text-xs text-gray-500">{seq.enrolled_count} enrolled · {seq.completed_count} completed</div>
              </button>
            ))}
          </div>
        </Card>

        <Card className="p-6 lg:col-span-2">
          {selectedSequence ? (
            <div className="space-y-6">
              <div className="flex items-center justify-between">
                <div>
                  <h3 className="text-lg font-semibold">{selectedSequence.name}</h3>
                  <p className="text-sm text-gray-500">{selectedSequence.description || "No description"}</p>
                </div>
                <Button onClick={() => setShowStepForm(!showStepForm)}>{showStepForm ? "Cancel" : "Add Step"}</Button>
              </div>

              {showStepForm && (
                <div className="space-y-4 border rounded-lg p-4">
                  <div>
                    <label className="block text-sm font-medium mb-1">Step Name</label>
                    <Input value={stepForm.name} onChange={e => setStepForm({ ...stepForm, name: e.target.value })} placeholder="Welcome email" />
                  </div>
                  <div>
                    <label className="block text-sm font-medium mb-1">Subject</label>
                    <Input value={stepForm.subject} onChange={e => setStepForm({ ...stepForm, subject: e.target.value })} placeholder="Welcome to {{name}}!" />
                  </div>
                  <div>
                    <label className="block text-sm font-medium mb-1">Body (HTML)</label>
                    <Textarea value={stepForm.body_html} onChange={e => setStepForm({ ...stepForm, body_html: e.target.value })} rows={6} placeholder="<p>Hi {{name}}, welcome!</p>" />
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="block text-sm font-medium mb-1">Delay (days)</label>
                      <Input type="number" value={stepForm.delay_days} onChange={e => setStepForm({ ...stepForm, delay_days: Number(e.target.value) })} />
                    </div>
                    <div>
                      <label className="block text-sm font-medium mb-1">Delay (hours)</label>
                      <Input type="number" value={stepForm.delay_hours} onChange={e => setStepForm({ ...stepForm, delay_hours: Number(e.target.value) })} />
                    </div>
                  </div>
                  <Button onClick={addStep} disabled={!stepForm.name || !stepForm.subject || !stepForm.body_html}>Add Step</Button>
                </div>
              )}

              <div className="space-y-3">
                {steps.map((step, i) => (
                  <div key={step.id} className="border rounded-lg p-4">
                    <div className="flex items-start justify-between">
                      <div>
                        <div className="font-medium">Step {i + 1}: {step.name}</div>
                        <div className="text-sm text-gray-500">Subject: {step.subject}</div>
                        <div className="text-sm text-gray-500">Delay: {step.delay_days}d {step.delay_hours}h</div>
                      </div>
                      <Button size="sm" variant="destructive" onClick={() => removeStep(step.id)}>Remove</Button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ) : (
            <div className="text-center text-gray-400 py-12">Select a sequence to view and edit its steps.</div>
          )}
        </Card>
      </div>
    </div>
  );
}

