"use client";

import { useState, useEffect } from "react";
import { Card } from "@/components/ui";
import { Button } from "@/components/ui";
import { Input } from "@/components/ui";
import { Textarea } from "@/components/marketing/ui";
import { Badge } from "@/components/marketing/ui";
import { Select, SelectItem } from "@/components/marketing/ui";
import { EMAIL_TEMPLATES, type EmailTemplate, personalizeTemplate, personalizeSubject, type PersonalizationContext } from "@/lib/email-marketing/templates";
import { listLists } from "@/lib/email-marketing/lists";

export function EmailBuilder() {
  const [lists, setLists] = useState<Array<{ id: string; name: string }>>([]);
  const [selectedTemplate, setSelectedTemplate] = useState<EmailTemplate | null>(null);
  const [subject, setSubject] = useState("");
  const [preheader, setPreheader] = useState("");
  const [html, setHtml] = useState("");
  const [listId, setListId] = useState("");
  const [saving, setSaving] = useState(false);
  const [previewCtx, setPreviewCtx] = useState<PersonalizationContext>({
    email: "john@example.com",
    first_name: "John",
    last_name: "Doe",
    company: "Acme",
    custom_fields: {},
    unsubscribe_url: "#unsubscribe",
    view_in_browser_url: "#view",
  });

  useEffect(() => {
    listLists().then(data => setLists(data || []));
  }, []);

  const selectTemplate = (template: EmailTemplate) => {
    setSelectedTemplate(template);
    setSubject(template.subject);
    setPreheader(template.preheader);
    setHtml(template.body_html);
  };

  const previewHtml = selectedTemplate
    ? personalizeTemplate(html, previewCtx)
    : "";

  const previewSubject = selectedTemplate
    ? personalizeSubject(subject, previewCtx)
    : "";

  const saveEmail = async () => {
    if (!subject || !html) return;
    setSaving(true);
    try {
      await fetch("/api/emails", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ name: subject, subject, preheader, body_html: html, list_id: listId || null, status: "draft" }),
      });
      alert("Email saved!");
    } catch (e) {
      console.error(e);
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <Card className="p-6 lg:col-span-2 space-y-6">
          <div>
            <h2 className="text-xl font-bold mb-4">Email Builder</h2>
            <div>
              <label className="block text-sm font-medium mb-2">Template</label>
              <div className="grid grid-cols-2 md:grid-cols-3 gap-2">
                {EMAIL_TEMPLATES.map(t => (
                  <button
                    key={t.id}
                    onClick={() => selectTemplate(t)}
                    className={`p-3 rounded-lg border text-left transition-colors ${
                      selectedTemplate?.id === t.id ? "border-indigo-500 bg-indigo-50" : "border-gray-200 hover:border-indigo-300"
                    }`}
                  >
                    <div className="font-medium text-sm">{t.name}</div>
                    <div className="text-xs text-gray-500 mt-1">{t.description}</div>
                  </button>
                ))}
              </div>
            </div>
          </div>

          {selectedTemplate && (
            <>
              <div>
                <label className="block text-sm font-medium mb-1">Subject</label>
                <Input value={subject} onChange={e => setSubject(e.target.value)} placeholder="Email subject" />
              </div>
              <div>
                <label className="block text-sm font-medium mb-1">Preheader</label>
                <Input value={preheader} onChange={e => setPreheader(e.target.value)} placeholder="Preview text" />
              </div>
              <div>
                <label className="block text-sm font-medium mb-1">Body (HTML)</label>
                <Textarea value={html} onChange={e => setHtml(e.target.value)} rows={12} />
              </div>
              <div>
                <label className="block text-sm font-medium mb-1">List</label>
                <Select value={listId} onValueChange={setListId}>
                  <SelectItem value="">No list</SelectItem>
                  {lists.map(l => <SelectItem key={l.id} value={l.id}>{l.name}</SelectItem>)}
                </Select>
              </div>
              <Button onClick={saveEmail} disabled={saving || !subject || !html}>
                {saving ? "Saving..." : "Save Email"}
              </Button>
            </>
          )}
        </Card>

        <Card className="p-6">
          <h3 className="font-semibold mb-4">Preview</h3>
          <div className="space-y-4">
            <div>
              <label className="block text-xs font-medium mb-1">Subject Preview</label>
              <div className="text-sm font-medium p-2 bg-gray-50 rounded">{previewSubject || "—"}</div>
            </div>
            <div>
              <label className="block text-xs font-medium mb-1">Preheader</label>
              <div className="text-xs text-gray-500 p-2 bg-gray-50 rounded">{preheader || "—"}</div>
            </div>
            <div>
              <label className="block text-xs font-medium mb-1">Personalization</label>
              <div className="space-y-2">
                <Input value={previewCtx.first_name} onChange={e => setPreviewCtx({ ...previewCtx, first_name: e.target.value })} placeholder="First name" />
                <Input value={previewCtx.last_name} onChange={e => setPreviewCtx({ ...previewCtx, last_name: e.target.value })} placeholder="Last name" />
                <Input value={previewCtx.company} onChange={e => setPreviewCtx({ ...previewCtx, company: e.target.value })} placeholder="Company" />
              </div>
            </div>
            <div>
              <label className="block text-xs font-medium mb-1">Rendered Preview</label>
              <div className="border rounded-lg p-2 bg-white max-h-96 overflow-auto">
                {previewHtml ? (
                  <div dangerouslySetInnerHTML={{ __html: previewHtml }} />
                ) : (
                  <div className="text-sm text-gray-400">Select a template to preview</div>
                )}
              </div>
            </div>
          </div>
        </Card>
      </div>
    </div>
  );
}

