"use client";

import { useState, useEffect } from "react";
import { Card } from "@/components/ui";
import { Button } from "@/components/ui";
import { Input } from "@/components/ui";
import { Badge } from "@/components/marketing/ui";
import { Select, SelectItem } from "@/components/marketing/ui";
import type { ABTest, ABVariant } from "@/lib/email-marketing/ab-testing";

export function ABTestManager() {
  const [tests, setTests] = useState<ABTest[]>([]);
  const [selectedTest, setSelectedTest] = useState<ABTest | null>(null);
  const [variants, setVariants] = useState<ABVariant[]>([]);
  const [showForm, setShowForm] = useState(false);
  const [showVariantForm, setShowVariantForm] = useState(false);
  const [form, setForm] = useState({ name: "", email_id: "", traffic_split: 0.5, winner_criteria: "open_rate" });
  const [variantForm, setVariantForm] = useState({ name: "", subject: "", body_html: "", is_control: false });

  useEffect(() => {
    fetchTests();
  }, []);

  const fetchTests = async () => {
    try {
      const res = await fetch("/api/email/ab-tests");
      const data = await res.json();
      setTests(data || []);
    } catch (e) {
      console.error(e);
    }
  };

  const selectTest = async (test: ABTest) => {
    setSelectedTest(test);
    try {
      const res = await fetch(`/api/email/ab-tests/variants?ab_test_id=${test.id}`);
      const data = await res.json();
      setVariants(data || []);
    } catch (e) {
      console.error(e);
    }
  };

  const createTest = async () => {
    if (!form.name) return;
    await fetch("/api/email/ab-tests", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(form),
    });
    setForm({ name: "", email_id: "", traffic_split: 0.5, winner_criteria: "open_rate" });
    setShowForm(false);
    fetchTests();
  };

  const addVariant = async () => {
    if (!selectedTest || !variantForm.name || !variantForm.subject || !variantForm.body_html) return;
    await fetch("/api/email/ab-tests/variants", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ ...variantForm, ab_test_id: selectedTest.id }),
    });
    setVariantForm({ name: "", subject: "", body_html: "", is_control: false });
    setShowVariantForm(false);
    selectTest(selectedTest);
  };

  const startTest = async (id: string) => {
    await fetch("/api/email/ab-tests/variants", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ id }),
    });
    fetchTests();
    if (selectedTest) selectTest(selectedTest);
  };

  const getWinner = async (id: string) => {
    const res = await fetch("/api/email/ab-tests/variants", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ id }),
    });
    const result = await res.json();
    alert(result.recommendation || "No winner yet");
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h2 className="text-xl font-bold">A/B Tests</h2>
        <Button onClick={() => setShowForm(!showForm)}>{showForm ? "Cancel" : "New Test"}</Button>
      </div>

      {showForm && (
        <Card className="p-6 space-y-4">
          <div>
            <label className="block text-sm font-medium mb-1">Test Name</label>
            <Input value={form.name} onChange={e => setForm({ ...form, name: e.target.value })} placeholder="Welcome email subject test" />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium mb-1">Traffic Split</label>
              <Input type="number" step="0.1" min="0" max="1" value={form.traffic_split} onChange={e => setForm({ ...form, traffic_split: Number(e.target.value) })} />
            </div>
            <div>
              <label className="block text-sm font-medium mb-1">Winner Criteria</label>
              <Select value={form.winner_criteria} onValueChange={v => setForm({ ...form, winner_criteria: v })}>
                <SelectItem value="open_rate">Open Rate</SelectItem>
                <SelectItem value="click_rate">Click Rate</SelectItem>
              </Select>
            </div>
          </div>
          <Button onClick={createTest} disabled={!form.name}>Create Test</Button>
        </Card>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <Card className="p-4 lg:col-span-1">
          <h3 className="font-semibold mb-3">Tests</h3>
          <div className="space-y-2">
            {tests.map(test => (
              <button
                key={test.id}
                onClick={() => selectTest(test)}
                className={`w-full text-left p-3 rounded-lg border transition-colors ${
                  selectedTest?.id === test.id ? "border-indigo-500 bg-indigo-50" : "border-gray-200 hover:border-indigo-300"
                }`}
              >
                <div className="font-medium text-sm">{test.name}</div>
                <div className="flex items-center gap-2 mt-1">
                  <Badge className={test.status === "running" ? "bg-green-100 text-green-800" : test.status === "completed" ? "bg-blue-100 text-blue-800" : "bg-gray-100 text-gray-800"}>
                    {test.status}
                  </Badge>
                  <span className="text-xs text-gray-500">{test.winner_criteria}</span>
                </div>
              </button>
            ))}
          </div>
        </Card>

        <Card className="p-6 lg:col-span-2">
          {selectedTest ? (
            <div className="space-y-6">
              <div className="flex items-center justify-between">
                <div>
                  <h3 className="text-lg font-semibold">{selectedTest.name}</h3>
                  <p className="text-sm text-gray-500">Status: {selectedTest.status} · Criteria: {selectedTest.winner_criteria}</p>
                </div>
                <div className="flex gap-2">
                  {selectedTest.status === "draft" && (
                    <Button size="sm" onClick={() => startTest(selectedTest.id)}>Start Test</Button>
                  )}
                  {selectedTest.status === "running" && (
                    <Button size="sm" variant="outline" onClick={() => getWinner(selectedTest.id)}>Calculate Winner</Button>
                  )}
                </div>
              </div>

              {selectedTest.status === "draft" && (
                <div className="border rounded-lg p-4 space-y-4">
                  <h4 className="font-medium">Add Variant</h4>
                  <div>
                    <label className="block text-sm font-medium mb-1">Variant Name</label>
                    <Input value={variantForm.name} onChange={e => setVariantForm({ ...variantForm, name: e.target.value })} placeholder="Subject A" />
                  </div>
                  <div>
                    <label className="block text-sm font-medium mb-1">Subject</label>
                    <Input value={variantForm.subject} onChange={e => setVariantForm({ ...variantForm, subject: e.target.value })} placeholder="Subject line" />
                  </div>
                  <div>
                    <label className="block text-sm font-medium mb-1">Body (HTML)</label>
                    <Input value={variantForm.body_html} onChange={e => setVariantForm({ ...variantForm, body_html: e.target.value })} placeholder="<p>Body content</p>" />
                  </div>
                  <Button onClick={addVariant} disabled={!variantForm.name || !variantForm.subject}>Add Variant</Button>
                </div>
              )}

              <div className="space-y-3">
                {variants.map(v => (
                  <div key={v.id} className="border rounded-lg p-4">
                    <div className="flex items-center justify-between mb-2">
                      <div className="font-medium">{v.name} {v.is_control && <Badge className="bg-blue-100 text-blue-800">Control</Badge>}</div>
                    </div>
                    <div className="text-sm text-gray-600 mb-1">Subject: {v.subject}</div>
                    <div className="grid grid-cols-4 gap-4 text-sm">
                      <div>Sends: {v.sends}</div>
                      <div>Opens: {v.opens}</div>
                      <div>Clicks: {v.clicks}</div>
                      <div>Bounces: {v.bounces}</div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ) : (
            <div className="text-center text-gray-400 py-12">Select a test to view variants.</div>
          )}
        </Card>
      </div>
    </div>
  );
}

