"use client";

import { useState, useEffect } from "react";
import { Card } from "@/components/ui";
import { Button } from "@/components/ui";
import { Badge } from "@/components/marketing/ui";

type AnalyticsData = {
  aggregated: {
    total_sends: number;
    total_opens: number;
    total_clicks: number;
    total_bounces: number;
    total_unsubscribes: number;
    total_spam: number;
    open_rate: number;
    click_rate: number;
    bounce_rate: number;
    unsubscribe_rate: number;
  };
  topEmails: Array<{ email_id: string; sends: number; opens: number; clicks: number; open_rate: number; click_rate: number }>;
  engagement: { total: number; subscribed: number; unsubscribed: number; bounced: number; pending: number };
  days: number;
};

export function EmailAnalytics() {
  const [data, setData] = useState<AnalyticsData | null>(null);
  const [loading, setLoading] = useState(true);
  const [days, setDays] = useState(30);

  useEffect(() => {
    fetchAnalytics();
  }, [days]);

  const fetchAnalytics = async () => {
    setLoading(true);
    try {
      const res = await fetch(`/api/email/analytics?days=${days}`);
      const data = await res.json();
      setData(data);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <Card className="p-8 text-center">
        <div className="text-sm text-gray-500">Loading analytics...</div>
      </Card>
    );
  }

  if (!data) {
    return (
      <Card className="p-8 text-center text-gray-500">
        No analytics data yet. Send some emails to see performance metrics.
      </Card>
    );
  }

  const { aggregated, topEmails, engagement } = data;

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h2 className="text-xl font-bold">Email Analytics</h2>
        <select
          value={days}
          onChange={e => setDays(Number(e.target.value))}
          className="p-2 border rounded-md text-sm"
        >
          <option value={7}>Last 7 days</option>
          <option value={30}>Last 30 days</option>
          <option value={90}>Last 90 days</option>
        </select>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-5 gap-4">
        <Card className="p-4">
          <div className="text-sm text-gray-500">Sent</div>
          <div className="text-2xl font-bold">{aggregated.total_sends.toLocaleString()}</div>
        </Card>
        <Card className="p-4">
          <div className="text-sm text-gray-500">Opens</div>
          <div className="text-2xl font-bold">{aggregated.total_opens.toLocaleString()}</div>
          <div className="text-xs text-gray-400">{aggregated.open_rate}% open rate</div>
        </Card>
        <Card className="p-4">
          <div className="text-sm text-gray-500">Clicks</div>
          <div className="text-2xl font-bold">{aggregated.total_clicks.toLocaleString()}</div>
          <div className="text-xs text-gray-400">{aggregated.click_rate}% click rate</div>
        </Card>
        <Card className="p-4">
          <div className="text-sm text-gray-500">Bounces</div>
          <div className="text-2xl font-bold">{aggregated.total_bounces.toLocaleString()}</div>
          <div className="text-xs text-gray-400">{aggregated.bounce_rate}% bounce rate</div>
        </Card>
        <Card className="p-4">
          <div className="text-sm text-gray-500">Unsubscribes</div>
          <div className="text-2xl font-bold">{aggregated.total_unsubscribes.toLocaleString()}</div>
          <div className="text-xs text-gray-400">{aggregated.unsubscribe_rate}% rate</div>
        </Card>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <Card className="p-6">
          <h3 className="text-lg font-semibold mb-4">Top Performing Emails</h3>
          {topEmails.length === 0 ? (
            <div className="text-sm text-gray-500">No email data yet.</div>
          ) : (
            <div className="space-y-3">
              {topEmails.map((email, i) => (
                <div key={email.email_id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                  <div>
                    <div className="font-medium text-sm">Email {email.email_id.slice(-8)}</div>
                    <div className="text-xs text-gray-500">{email.sends} sends</div>
                  </div>
                  <div className="flex gap-3 text-sm">
                    <div>{email.open_rate}% opens</div>
                    <div>{email.click_rate}% clicks</div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </Card>

        <Card className="p-6">
          <h3 className="text-lg font-semibold mb-4">List Engagement</h3>
          <div className="space-y-4">
            <div>
              <div className="flex justify-between mb-1">
                <span className="text-sm text-gray-600">Total Subscribers</span>
                <span className="font-medium">{engagement.total.toLocaleString()}</span>
              </div>
              <div className="w-full bg-gray-200 rounded-full h-2">
                <div className="bg-indigo-600 h-2 rounded-full" style={{ width: "100%" }} />
              </div>
            </div>
            <div>
              <div className="flex justify-between mb-1">
                <span className="text-sm text-gray-600">Subscribed</span>
                <span className="font-medium">{engagement.subscribed.toLocaleString()}</span>
              </div>
              <div className="w-full bg-gray-200 rounded-full h-2">
                <div className="bg-green-500 h-2 rounded-full" style={{ width: `${engagement.total > 0 ? (engagement.subscribed / engagement.total) * 100 : 0}%` }} />
              </div>
            </div>
            <div>
              <div className="flex justify-between mb-1">
                <span className="text-sm text-gray-600">Unsubscribed</span>
                <span className="font-medium">{engagement.unsubscribed.toLocaleString()}</span>
              </div>
              <div className="w-full bg-gray-200 rounded-full h-2">
                <div className="bg-red-500 h-2 rounded-full" style={{ width: `${engagement.total > 0 ? (engagement.unsubscribed / engagement.total) * 100 : 0}%` }} />
              </div>
            </div>
            <div>
              <div className="flex justify-between mb-1">
                <span className="text-sm text-gray-600">Bounced</span>
                <span className="font-medium">{engagement.bounced.toLocaleString()}</span>
              </div>
              <div className="w-full bg-gray-200 rounded-full h-2">
                <div className="bg-yellow-500 h-2 rounded-full" style={{ width: `${engagement.total > 0 ? (engagement.bounced / engagement.total) * 100 : 0}%` }} />
              </div>
            </div>
          </div>
        </Card>
      </div>
    </div>
  );
}

